                new() { Titulo = "121. Que acontece na agonia do Getsemani?", Texto = "Apesar do horror da morte, a vontade humana do Filho adere à vontade do Pai para nos salvar." },
                new() { Titulo = "122. Quais os efeitos do sacrifício de Cristo na cruz?", Texto = "Jesus ofereceu a vida em sacrifício de expiação, reparando culpas pela obediência do amor até à morte." },
                new() { Titulo = "123. Por que Jesus convida os discípulos a tomar a sua cruz?", Texto = "Quer associá-los ao seu sacrifício redentor, sendo os primeiros a receber os seus benefícios." },
                new() { Titulo = "124. Em que condições estava o corpo de Cristo no sepulcro?", Texto = "Conheceu verdadeira morte e sepultura. O poder divino preservou o corpo da corrupção." },
                new() { Titulo = "125. O que são «os infernos» aos quais Jesus desceu?", Texto = "Mansão dos mortos. Jesus alcançou os justos que esperavam o Redentor, libertando-os do inferno." },
                new() { Titulo = "126. Que lugar ocupa a Ressurreição na fé?", Texto = "A verdade culminante da fé em Cristo, essencial junto com a Cruz no Mistério pascal." },
                new() { Titulo = "127. Que «sinais» atestam a Ressurreição?", Texto = "Túmulo vazio, aparições aos discípulos começando com as mulheres e Pedro, depois aos Doze." },
                new() { Titulo = "128. Por que a Ressurreição é transcendente?", Texto = "Embora histórica e comprovável, é entrada na glória divina, mistério de fé transcendente." },
                new() { Titulo = "129. Qual é o estado do corpo ressuscitado de Jesus?", Texto = "Ressuscitado não é volta à vida terrena, mas corpo glorioso com propriedades divinas." },
                new() { Titulo = "130. De que modo a Ressurreição é obra da Trindade?", Texto = "Obra transcendente de Deus. As três Pessoas atuam segundo o que lhes é próprio." },
                new() { Titulo = "131. Qual o sentido e importância da Ressurreição?", Texto = "Culmina a Encarnação, confirma a divindade de Cristo e realiza todas as promessas divinas." },
                new() { Titulo = "132. O que significa a Ascensão?", Texto = "Após quarenta dias, Cristo sobe ao céu e senta-se à direita do Pai, reinando com a sua humanidade." },
                new() { Titulo = "133. Como reina agora o Senhor Jesus?", Texto = "Senhor do cosmos e da história, Cabeça da Igreja, Reino já presente como germe na Igreja." },
                new() { Titulo = "134. Como se realizará a vinda do Senhor na glória?", Texto = "Após último abalo cósmico, a vinda gloriosa acontecerá com o triunfo definitivo e o Juízo final." },
                new() { Titulo = "135. Como Cristo julgará os vivos e mortos?", Texto = "Com o poder de Redentor. Os segredos dos corações serão revelados segundo o procedimento de cada um." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "Creio no Espírito Santo",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "136. O que quer dizer a Igreja profissando: «Creio no Espírito Santo»?", Texto = "Professar a terceira Pessoa da Santíssima Trindade, que procede do Pai e do Filho." },
                new() { Titulo = "137. Por que as missões do Filho e do Espírito são inseparáveis?", Texto = "Distintos mas inseparáveis. Quando o Pai envia o Filho, envia o Espírito que nos une a Cristo." },
                new() { Titulo = "138. Quais são as designações do Espírito Santo?", Texto = "«Espírito Santo» é nome próprio. Jesus chama-lhe Paráclito e Espírito de Verdade." },
                new() { Titulo = "139. Com que símbolos se representa o Espírito Santo?", Texto = "Água viva, unção com óleo, fogo, nuvem, imposição de mãos, pomba." },
                new() { Titulo = "140. O que significa que o Espírito «falou pelos profetas»?", Texto = "Todos foram inspirados pelo Espírito para falar em nome de Deus, culminando em Cristo." },
                new() { Titulo = "141. O que o Espírito Santo realiza em João Baptista?", Texto = "Cheio de Espírito Santo, prepara «povo bem disposto» ao Senhor e anuncia Cristo." },
                new() { Titulo = "142. Qual é a obra do Espírito em Maria?", Texto = "Realiza as expectativas do Antigo Testamento, enche-a de graça e torna fecunda a virgindade." },
                new() { Titulo = "143. Qual a relação entre o Espírito e Cristo na missão terrena?", Texto = "O Filho é consagrado Messias pela unção do Espírito desde a Encarnação, revelando-O." },
                new() { Titulo = "144. O que acontece no Pentecostes?", Texto = "Cristo glorificado infunde o Espírito em abundância, revelando-O como Pessoa divina." },
                new() { Titulo = "145. Que faz o Espírito Santo na Igreja?", Texto = "Edifica, anima e santifica a Igreja, tornando-a viva com a vida da Santíssima Trindade." },
                new() { Titulo = "146. Como atuam Cristo e o seu Espírito nos fiéis?", Texto = "Por meio dos sacramentos, Cristo comunica o Espírito e a graça que produzem vida nova." },
                new() { Titulo = "147. O que significa a palavra Igreja?", Texto = "Designa o povo que Deus convoca, assembleia de filhos de Deus e corpo de Cristo." },
                new() { Titulo = "148. Há outros nomes e imagens para a Igreja?", Texto = "Muitas: povo de Deus, corpo de Cristo, redil, rebanho, vinha, templo, esposa, mãe." },
                new() { Titulo = "149. Quais são as origens e realização da Igreja?", Texto = "Origem no desígnio eterno de Deus, preparada na Antiga Aliança, fundada por Cristo." },
                new() { Titulo = "150. Qual é a missão da Igreja?", Texto = "Anunciar e instaurar no meio de todos os povos o Reino de Deus inaugurado por Cristo." },
                new() { Titulo = "151. Em que sentido a Igreja é Mistério?", Texto = "Na realidade visível está presente realidade espiritual divina, descobrível pelos olhos da fé." },
                new() { Titulo = "152. Que significa Igreja é sacramento universal de salvação?", Texto = "É sinal e instrumento da reconciliação de toda a humanidade com Deus." },
                new() { Titulo = "153. Por que a Igreja é povo de Deus?", Texto = "Porque Deus quis santificar e salvar os homens não isolados mas constituindo povo único." },
                new() { Titulo = "154. Quais são as características do povo de Deus?", Texto = "Origem em Deus Pai, cabeça Cristo, dignidade de filhos de Deus, lei do amor novo." },
                new() { Titulo = "155. Como o povo participa das três funções de Cristo?", Texto = "Participa no ministério sacerdotal, profético e real de Cristo." },
                new() { Titulo = "156. Como a Igreja é corpo de Cristo?", Texto = "Por meio do Espírito, Cristo une intimamente a Si os seus fiéis, formando um só corpo." },
                new() { Titulo = "157. Quem é a cabeça deste corpo?", Texto = "Cristo «é a Cabeça do corpo, que é a Igreja», vivendo dela, nela e para ela." },
                new() { Titulo = "158. Por que a Igreja é chamada esposa de Cristo?", Texto = "O Senhor definiu-se como «Esposo», unindo a Igreja a Si por Aliança eterna." },
                new() { Titulo = "159. Por que a Igreja é templo do Espírito Santo?", Texto = "Porque o Espírito Santo reside no corpo que é a Igreja, edificando-a na caridade." },
                new() { Titulo = "160. Que são carismas?", Texto = "Dons especiais do Espírito concedidos para o bem dos homens e edificação da Igreja." },
                new() { Titulo = "161. Por que a Igreja é una?", Texto = "Origem na unidade da Trindade, cabeça Cristo, alma o Espírito Santo, unindo todos." },
                new() { Titulo = "162. Onde subsiste a única Igreja de Cristo?", Texto = "Subsiste na Igreja católica, governada pelo sucessor de Pedro e pelos Bispos em comunhão." },
                new() { Titulo = "163. Como considerar os cristãos não católicos?", Texto = "Encontram-se neles elementos de santificação e verdade. Reconhecemo-los como irmãos em Cristo." },
                new() { Titulo = "164. Como empenhar-se pela unidade dos cristãos?", Texto = "Dom de Cristo. Realiza-se por conversão do coração, oração e conhecimento fraterno." },
                new() { Titulo = "165. Em que sentido a Igreja é santa?", Texto = "Porque Deus Santíssimo é o seu autor, Cristo a santificou e o Espírito a vivifica." },
                new() { Titulo = "166. Por que a Igreja se chama católica?", Texto = "É universal, porque nela está presente Cristo, anunciando a totalidade da fé." },
                new() { Titulo = "167. É católica a Igreja particular?", Texto = "Sim. Toda Igreja particular (diocese/eparquia) é católica em comunhão com o Bispo." },
                new() { Titulo = "168. Quem pertence à Igreja católica?", Texto = "Todos os homens, de diferentes modos. Plenamente incorporados os que estão em comunhão plena." },
                new() { Titulo = "169. Qual a relação da Igreja com o povo judeu?", Texto = "Reconhece relação ao ter Deus escolhido esse povo para acolher a sua Palavra." },
                new() { Titulo = "170. Que ligação há entre a Igreja e as religiões não cristãs?", Texto = "Laço comum em origem e fim. Tudo de bom nas religiões vem de Deus." },
                new() { Titulo = "171. Que significa: «Fora da Igreja não há salvação»?", Texto = "Toda a salvação vem de Cristo-Cabeça por meio da Igreja, seu corpo." },
                new() { Titulo = "172. Por que a Igreja deve anunciar o Evangelho ao mundo?", Texto = "Cristo ordenou: «ide e ensinai todas as nações», porque Deus quer a salvação de todos." },
                new() { Titulo = "173. Como é que a Igreja é missionária?", Texto = "Guiada pelo Espírito Santo, continua no curso da história a missão do próprio Cristo." },
                new() { Titulo = "174. Por que a Igreja é apostólica?", Texto = "Pela sua origem, sendo construída sobre o fundamento dos Apóstolos, seu ensino e estrutura." },
                new() { Titulo = "175. Em que consiste a missão dos Apóstolos?", Texto = "«Apóstolo» significa enviado. Jesus fez os Doze testemunhas da ressurreição e fundamentos." },
                new() { Titulo = "176. O que é a sucessão apostólica?", Texto = "Transmissão mediante sacramento da Ordem da missão e poder dos Apóstolos aos Bispos." },
                new() { Titulo = "177. Quem são os fiéis?", Texto = "Aqueles que, incorporados em Cristo pelo Baptismo, são constituídos membros do povo de Deus." },
                new() { Titulo = "178. Como é formado o povo de Deus?", Texto = "Existem os ministros sagrados que receberam o sacramento da Ordem e, os outros, são leigos." },
                new() { Titulo = "179. Por que Cristo instituiu a hierarquia eclesiástica?", Texto = "Com missão de apascentar o povo de Deus em seu nome, dando-lhe autoridade." },
                new() { Titulo = "180. Como se atua a dimensão colegial do ministério?", Texto = "À exemplo dos Apóstolos, a união dos ministros está ao serviço da comunhão dos fiéis." },
                new() { Titulo = "181. Por que o ministério tem carácter pessoal?", Texto = "Cada um é responsável diante de Cristo, que pessoalmente o chamou." },
                new() { Titulo = "182. Qual é a missão do Papa?", Texto = "Sucessor de S. Pedro, é perpétuo e visível princípio e fundamento da unidade da Igreja." },
                new() { Titulo = "183. Qual é a missão do colégio dos Bispos?", Texto = "Em comunhão com o Papa exercem também supremo e pleno poder sobre a Igreja." },
                new() { Titulo = "184. Como os Bispos exercem a missão de ensinar?", Texto = "Têm o dever de anunciar o Evangelho a todos, fielmente e com autoridade." },
                new() { Titulo = "185. Quando se exerce a infalibilidade do Magistério?", Texto = "Quando o Romano Pontífice ou o Colégio Episcopal proclamam com ato definitivo uma doutrina." },
                new() { Titulo = "186. Como os Bispos exercem o ministério de santificar?", Texto = "Dispensando a graça de Cristo, mediante o ministério da palavra e dos sacramentos." },
                new() { Titulo = "187. Como os Bispos exercem a função de governar?", Texto = "Cada Bispo exerce colegialmente solicitude por todas as Igrejas particulares." },
                new() { Titulo = "188. Qual é a vocação dos fiéis leigos?", Texto = "Procurar o Reino de Deus, iluminando e ordenando as realidades temporais segundo Deus." },
                new() { Titulo = "189. Como os leigos participam na função sacerdotal de Cristo?", Texto = "Oferecendo sacrifício espiritual, sobretudo na Eucaristia, com a sua vida e todas as obras." },
                new() { Titulo = "190. Como participam na função profética?", Texto = "Acolhendo na fé a Palavra de Cristo e anunciando-a ao mundo com testemunho." },
                new() { Titulo = "191. Como participam na função real?", Texto = "Tendo recebido poder de vencer o pecado mediante abnegação e santidade de vida." },
                new() { Titulo = "192. O que é a vida consagrada?", Texto = "Estado de vida reconhecido pela Igreja, resposta livre a chamamento particular." },
            }
        },

        // ─────────────────────────────────────────────────────────────────────
        // SEGUNDA PARTE: A CELEBRAÇÃO DO MISTÉRIO CRISTÃO
        // ─────────────────────────────────────────────────────────────────────

        new CatecismoPtTopico
        {
            Titulo = "A Celebração Sacramental do Mistério Pascal",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "233. Quem age na liturgia?", Texto = "Na liturgia age «o Cristo todo inteiro» (Christus Totus), Cabeça e Corpo. Como sumo-sacerdote, Ele celebra com o seu Corpo, que é a Igreja celeste e terrestre." },
                new() { Titulo = "234. Por quem é celebrada a liturgia celeste?", Texto = "A liturgia celeste é celebrada pelos anjos, pelos santos da Antiga e da Nova Aliança, em particular pela Mãe de Deus, pelos Apóstolos, pelos mártires e por uma «numerosa multidão, que ninguém pode contar, de todas as nações, tribos, povos e línguas» (Ap 7,9). Quando nos sacramentos celebramos o mistério da salvação, participamos nesta liturgia eterna." },
                new() { Titulo = "235. Como é que a Igreja na terra celebra a liturgia?", Texto = "A Igreja, na terra, celebra a liturgia, como povo sacerdotal, no qual cada um actua segundo a própria função, na unidade do Espírito Santo: os baptizados oferecem-se em sacrifício espiritual; os ministros ordenados celebram segundo a Ordem recebida para o serviço de todos os membros da Igreja; os Bispos e os presbíteros agem na pessoa de Cristo Cabeça." },
                new() { Titulo = "236. Como é celebrada a liturgia?", Texto = "A celebração litúrgica é tecida de sinais e de símbolos, cujo significado, radicado na criação e nas culturas humanas, se esclarece nos acontecimentos da Antiga Aliança e se revela plenamente na Pessoa e na obra de Cristo." },
                new() { Titulo = "237. Donde provêm os sinais sacramentais?", Texto = "Alguns provêm da criação (luz, água, fogo, pão, vinho, óleo); outros da vida social (lavar, ungir, partir o pão); outros da história da salvação na Antiga Aliança (os ritos da Páscoa, os sacrifícios, a imposição das mãos, as consagrações). Estes sinais, assumidos por Cristo, tornam-se portadores da acção salvífica e de santificação." },
                new() { Titulo = "238. Qual o nexo entre as acções e as palavras na celebração sacramental?", Texto = "Na celebração sacramental, acções e palavras estão intimamente ligadas. Mesmo que as acções simbólicas sejam já em si uma linguagem, é todavia necessário que as palavras do rito acompanhem e vivifiquem estas acções. Enquanto sinais e ensino, as palavras e os gestos são inseparáveis, uma vez que realizam aquilo que significam." },
                new() { Titulo = "239. Quais os critérios do canto e da música na celebração litúrgica?", Texto = "Uma vez que o canto e a música estão intimamente conexos com a acção litúrgica, eles devem respeitar os seguintes critérios: a conformidade à doutrina católica dos textos; a beleza expressiva da oração; a qualidade da música; a participação da assembleia; a riqueza cultural do Povo de Deus e o carácter sacro e solene da celebração. «Quem canta reza duas vezes» (S. Agostinho)." },
                new() { Titulo = "240. Qual a finalidade das imagens sagradas?", Texto = "A imagem de Cristo é o ícone litúrgico por excelência. As outras, que representam Nossa Senhora e os santos, significam Cristo, que nelas é glorificado. Elas proclamam a mesma mensagem evangélica que a Sagrada Escritura transmite através da palavra e ajudam a despertar e a alimentar a fé dos fiéis." },
                new() { Titulo = "241. Qual é o centro do tempo litúrgico?", Texto = "O centro do tempo litúrgico é o Domingo, fundamento e núcleo de todo o ano litúrgico, que tem o seu cume na Páscoa anual, a festa das festas." },
                new() { Titulo = "242. Qual é a função do ano litúrgico?", Texto = "No ano litúrgico, a Igreja celebra todo o Mistério de Cristo, da Encarnação até à sua vinda gloriosa. Nos dias estabelecidos, a Igreja venera com especial amor a bem-aventurada Virgem Maria Mãe de Deus e também faz memória dos Santos, que por Cristo viveram, com Ele sofreram e com Ele são glorificados." },
                new() { Titulo = "243. O que é a liturgia das horas?", Texto = "A liturgia das horas, oração pública e comum da Igreja, é a oração de Cristo com o seu Corpo, a Igreja. Por ela, o Mistério de Cristo, que celebramos na Eucaristia, santifica e transfigura o tempo de cada dia. Ela compõe-se principalmente de Salmos e de outros textos bíblicos, e também de leituras dos Padres e dos mestres espirituais." },
                new() { Titulo = "244. A Igreja tem necessidade de lugares para celebrar a liturgia?", Texto = "O culto «em espírito e verdade» (Jo 4,24) da Nova Aliança não está ligado a nenhum lugar exclusivo, porque Cristo é o verdadeiro templo de Deus. Todavia o Povo de Deus, na sua condição terrena, tem necessidade de lugares nos quais a comunidade se possa reunir para celebrar a liturgia." },
                new() { Titulo = "245. O que são os edifícios sagrados?", Texto = "São as casas de Deus, símbolo da Igreja que vive num lugar e também da morada celeste. São lugares de oração, nos quais a Igreja celebra sobretudo a Eucaristia e adora Cristo realmente presente no tabernáculo." },
                new() { Titulo = "246. Quais são os lugares privilegiados no interior dos edifícios sagrados?", Texto = "São: o altar, o tabernáculo, o lugar onde se guarda o santo crisma e os outros óleos sagrados, a cadeira do Bispo (cátedra) ou do presbítero, o ambão, a fonte baptismal, o confessionário." },
                new() { Titulo = "247. Porque é que a Igreja celebra o único Mistério de Cristo segundo tradições litúrgicas diferentes?", Texto = "Porque a insondável riqueza do Mistério de Cristo não pode ser esgotada por uma única tradição litúrgica. Desde as origens, esta riqueza encontrou, nos vários povos e culturas, expressões caracterizadas por uma admirável variedade e complementaridade." },
                new() { Titulo = "248. Qual é o critério que assegura a unidade na diversidade?", Texto = "É a fidelidade à Tradição Apostólica, isto é, à comunhão na fé e nos sacramentos recebidos dos Apóstolos, comunhão que é significada e garantida pela sucessão apostólica. A Igreja é católica: pode, portanto, integrar na sua unidade todas as verdadeiras riquezas das culturas." },
                new() { Titulo = "249. Na liturgia, tudo é imutável?", Texto = "Na liturgia, sobretudo na dos sacramentos, existem elementos imutáveis, porque de instituição divina, e dos quais a Igreja é guardiã. Existem depois elementos susceptíveis de mudança, que a Igreja tem o poder, e muitas vezes o dever, de adaptar às culturas dos diferentes povos." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "Os Sete Sacramentos da Igreja",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "250. Como agrupar os sacramentos da Igreja?", Texto = "Em: sacramentos da iniciação cristã (Baptismo, Confirmação e Eucaristia); sacramentos da cura (Penitência e Unção dos enfermos); sacramentos ao serviço da comunhão e da missão (Ordem e Matrimónio). Os sacramentos tocam todas as etapas e momentos importantes da vida cristã. Todos os sacramentos estão ordenados para a Eucaristia «como para o seu fim» (S. Tomás de Aquino)." },
                new() { Titulo = "251. Como se realiza a iniciação cristã?", Texto = "Realiza-se mediante os sacramentos que lançam os alicerces da vida cristã: os fiéis, renascidos pelo Baptismo, são fortalecidos pela Confirmação e alimentados pela Eucaristia." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "O Sacramento do Baptismo",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "252. Quais os nomes do primeiro sacramento da iniciação?", Texto = "Antes de mais, chama-se Baptismo por causa do rito central com que é celebrado: baptizar significa «imergir» na água. O que é baptizado é imerso na morte de Cristo e ressurge com Ele como «nova criatura» (2 Cor 5,17). Chama-se também «banho da regeneração e da renovação no Espírito Santo» (Tit 3,5) e «iluminação», porque o baptizado se torna «filho da luz» (Ef 5,8)." },
                new() { Titulo = "253. Como é prefigurado o Baptismo na Antiga Aliança?", Texto = "Na Antiga Aliança encontram-se várias prefigurações do Baptismo: a água, fonte de vida e de morte; a arca de Noé, que salva por meio da água; a passagem do Mar Vermelho, que liberta Israel da escravidão do Egipto; a travessia do Jordão, que introduz Israel na terra prometida, imagem da vida eterna." },
                new() { Titulo = "254. Quem conduz ao cumprimento tais prefigurações?", Texto = "É Jesus Cristo, o qual, no início da sua vida pública, se fez baptizar por João Baptista, no Jordão: na cruz, do seu lado trespassado, derramou sangue e água, sinais do Baptismo e da Eucaristia, e depois da Ressurreição confia aos Apóstolos esta missão: «Ide e ensinai todos os povos, baptizando-os no nome do Pai e do Filho e do Espírito Santo» (Mt 28,19-20)." },
                new() { Titulo = "255. Desde quando e a quem é que a Igreja administra o Baptismo?", Texto = "Desde o dia de Pentecostes que a Igreja administra o Baptismo a quem crê em Jesus Cristo." },
                new() { Titulo = "256. Em que consiste o rito essencial do Baptismo?", Texto = "O rito essencial deste sacramento consiste em imergir na água o candidato ou em derramar a água sobre a sua cabeça, enquanto é invocado o Nome do Pai e do Filho e do Espírito Santo." },
                new() { Titulo = "257. Quem pode receber o Baptismo?", Texto = "É capaz para receber o Baptismo toda a pessoa ainda não baptizada." },
                new() { Titulo = "258. Porque é que a Igreja baptiza as crianças?", Texto = "Porque tendo nascido com o pecado original, elas têm necessidade de ser libertadas do poder do Maligno e de ser transferidas para o reino da liberdade dos filhos de Deus." },
                new() { Titulo = "259. O que se requer dum baptizando?", Texto = "Ao baptizando é exigida a profissão de fé, expressa pessoalmente no caso do adulto, ou então por parte dos pais e da Igreja no caso da criança. Também o padrinho ou madrinha e toda a comunidade eclesial têm uma parte de responsabilidade na preparação para o Baptismo (catecumenado), bem como no desenvolvimento da fé e da graça baptismal." },
                new() { Titulo = "260. Quem pode baptizar?", Texto = "Os ministros ordinários do Baptismo são o Bispo e o presbítero; na Igreja latina, também o diácono. Em caso de necessidade, qualquer pessoa pode baptizar, desde que entenda fazer o que faz a Igreja e derrame água sobre a cabeça do candidato, dizendo a fórmula trinitária baptismal: «Eu te baptizo em Nome do Pai e do Filho e do Espírito Santo»." },
                new() { Titulo = "261. É necessário o Baptismo para a salvação?", Texto = "O Baptismo é necessário para a salvação daqueles a quem foi anunciado o Evangelho e que têm a possibilidade de pedir este sacramento." },
                new() { Titulo = "262. É possível ser salvo sem o Baptismo?", Texto = "Porque Cristo morreu para a salvação de todos, podem ser salvos mesmo sem o Baptismo os que morrem por causa da fé (Baptismo de sangue), os catecúmenos, e todos os que sob o impulso da graça, sem conhecer Cristo e a Igreja, procuram sinceramente a Deus e se esforçam por cumprir a sua vontade (Baptismo de desejo). Quanto às crianças mortas sem Baptismo, a Igreja na sua liturgia confia-as à misericórdia de Deus." },
                new() { Titulo = "263. Quais são os efeitos do Baptismo?", Texto = "O Baptismo perdoa o pecado original, todos os pecados pessoais e as penas devidas ao pecado; faz participar na vida divina trinitária mediante a graça santificante; incorpora em Cristo e na Igreja; faz participar no sacerdócio de Cristo e constitui o fundamento da comunhão entre todos os cristãos; confere as virtudes teologais e os dons do Espírito Santo. O baptizado pertence para sempre a Cristo: com efeito, é assinalado com o selo indelével de Cristo (carácter)." },
                new() { Titulo = "264. Que significado assume o nome cristão recebido no Baptismo?", Texto = "O nome é importante, porque Deus conhece cada um pelo nome, isto é, na sua unicidade. Com o Baptismo, o cristão recebe na Igreja o próprio nome, de preferência o de um santo, de maneira que este ofereça ao baptizado um modelo de santidade e lhe assegure a sua intercessão junto de Deus." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "O Sacramento da Confirmação",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "265. Qual é o lugar da Confirmação no desígnio divino da salvação?", Texto = "Na Antiga Aliança, os profetas anunciaram a comunicação do Espírito do Senhor ao Messias esperado e a todo o povo messiânico. Toda a vida e missão de Jesus se desenvolvem numa total comunhão com o Espírito Santo. Os Apóstolos recebem o Espírito Santo no Pentecostes e anunciam «as grandes obras de Deus» (Act 2,11). Comunicam aos neófitos, através da imposição das mãos, o dom do mesmo Espírito. Ao longo dos séculos, a Igreja continuou a viver do Espírito e a comunicá-lo aos seus filhos." },
                new() { Titulo = "266. Porque se chama Crisma ou Confirmação?", Texto = "Chama-se Crisma (nas Igrejas Orientais: Crismação com o Santo Myron) por causa do rito essencial que é a unção. Chama-se Confirmação, porque confirma e reforça a graça baptismal." },
                new() { Titulo = "267. Qual o rito essencial da Confirmação?", Texto = "O rito essencial da Confirmação é a unção com o santo crisma (óleo misturado com bálsamo, consagrado pelo Bispo), feita com a imposição da mão por parte do ministro que pronuncia as palavras sacramentais próprias do rito. No Ocidente, tal unção é feita sobre a fronte do baptizado com as palavras: «Recebe por este sinal, o Espírito Santo, o Dom de Deus». Nas Igrejas Orientais de rito bizantino, a unção faz-se também noutras partes do corpo, com a fórmula: «Selo do dom do Espírito Santo»." },
                new() { Titulo = "268. Qual é o efeito da Confirmação?", Texto = "O efeito da Confirmação é a efusão especial do Espírito Santo, como no Pentecostes. Tal efusão imprime na alma um carácter indelével e traz consigo um crescimento da graça baptismal: enraíza mais profundamente na filiação divina; une mais firmemente a Cristo e à sua Igreja; revigora na alma os dons do Espírito Santo; dá uma força especial para testemunhar a fé cristã." },
                new() { Titulo = "269. Quem pode receber este sacramento?", Texto = "Pode e deve recebê-lo, uma só vez, quem já foi baptizado, o qual, para o receber eficazmente, deve estar em estado de graça." },
                new() { Titulo = "270. Quem é o ministro da Confirmação?", Texto = "O ministro originário é o Bispo. Assim se manifesta o laço do crismado com a Igreja na sua dimensão apostólica. Quando o presbítero confere este sacramento, o laço com o Bispo e com a Igreja é expresso pelo presbítero, colaborador do Bispo, e pelo santo crisma, consagrado pelo Bispo." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "O Sacramento da Eucaristia",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "271. O que é a Eucaristia?", Texto = "É o próprio sacrifício do Corpo e do Sangue do Senhor Jesus, que Ele instituiu para perpetuar o sacrifício da cruz no decorrer dos séculos até ao seu regresso, confiando assim à sua Igreja o memorial da sua Morte e Ressurreição. É o sinal da unidade, o vínculo da caridade, o banquete pascal, em que se recebe Cristo, a alma se enche de graça e nos é dado o penhor da vida eterna." },
                new() { Titulo = "272. Quando é que Jesus Cristo instituiu a Eucaristia?", Texto = "Instituiu-a na Quinta Feira Santa, «na noite em que foi entregue» (1 Cor 11,23), ao celebrar a Última Ceia com os seus Apóstolos." },
                new() { Titulo = "273. Como é que a instituiu?", Texto = "Depois de reunir os Apóstolos no Cenáculo, Jesus tomou nas suas mãos o pão, partiu-o e deu-lho dizendo: «Tomai e comei todos: isto é o meu corpo entregue por vós». Depois tomou nas suas mãos o cálice do vinho e disse-lhes: «Tomai e bebei todos: este é o cálice do meu sangue para a nova e eterna aliança, derramado por vós e por todos para a remissão dos pecados. Fazei isto em memória de mim»." },
                new() { Titulo = "274. O que significa a Eucaristia na vida da Igreja?", Texto = "É fonte e cume da vida cristã. Na Eucaristia, atingem o auge a acção santificadora de Deus em nosso favor e o nosso culto para com Ele. Nela está contido todo o tesouro espiritual da Igreja: o próprio Cristo, nossa Páscoa. A comunhão da vida divina e a unidade do Povo de Deus são significadas e realizadas na Eucaristia. Pela celebração eucarística unimo-nos desde já à liturgia do Céu e antecipamos a vida eterna." },
                new() { Titulo = "275. Como é chamado este sacramento?", Texto = "A insondável riqueza deste sacramento exprime-se com diferentes nomes: Eucaristia, Santa Missa, Ceia do Senhor, Fracção do pão, Celebração Eucarística, Memorial da paixão, morte e ressurreição do Senhor, Santo Sacrifício, Santa e Divina Liturgia, Santos Mistérios, Santíssimo Sacramento do altar, Santa Comunhão." },
                new() { Titulo = "276. Qual o lugar da Eucaristia no desígnio da salvação?", Texto = "Na Antiga Aliança, a Eucaristia é preanunciada sobretudo na ceia pascal anual, celebrada cada ano pelos judeus com os pães ázimos. Jesus anuncia-a no seu ensino e institui-a, celebrando com os seus Apóstolos a última Ceia, durante um banquete pascal. A Igreja, fiel ao mandamento do Senhor: «Fazei isto em memória de mim» (1 Cor 11,24), sempre celebrou a Eucaristia, sobretudo ao Domingo." },
                new() { Titulo = "277. Como se desenrola a celebração da Eucaristia?", Texto = "Desenrola-se em dois grandes momentos que formam um só acto de culto: a liturgia da Palavra, que compreende a proclamação e escuta da Palavra de Deus; e a liturgia eucarística, que compreende a apresentação do pão e do vinho, a oração ou anáfora contendo as palavras da consagração, e a comunhão." },
                new() { Titulo = "278. Quem é o ministro da celebração da Eucaristia?", Texto = "É o sacerdote (Bispo ou presbítero), validamente ordenado, que age na Pessoa de Cristo Cabeça e em nome da Igreja." },
                new() { Titulo = "279. Quais os elementos essenciais e necessários para realizar a Eucaristia?", Texto = "São o pão de trigo e o vinho da videira." },
                new() { Titulo = "280. Como é que a Eucaristia é memorial do sacrifício de Cristo?", Texto = "A Eucaristia é memorial no sentido que torna presente e actual o sacrifício que Cristo ofereceu ao Pai, uma vez por todas, na cruz. O carácter sacrificial manifesta-se nas próprias palavras da instituição: «Isto é o meu corpo, que vai ser entregue por vós» e «este cálice é a nova aliança no meu sangue, que vai ser derramado por vós» (Lc 22,19-20). O sacrifício da cruz e o sacrifício da Eucaristia são um único sacrifício." },
                new() { Titulo = "281. Como é que a Igreja participa no sacrifício eucarístico?", Texto = "Na Eucaristia, o sacrifício de Cristo torna-se também o sacrifício dos membros do seu Corpo. A vida dos fiéis, o seu louvor, o seu sofrimento, a sua oração, o seu trabalho são unidos aos de Cristo. Enquanto sacrifício, a Eucaristia é também oferecida por todos os fiéis vivos e defuntos, em reparação dos pecados e para obter de Deus benefícios espirituais e temporais." },
                new() { Titulo = "282. Como é que Jesus está presente na Eucaristia?", Texto = "Jesus Cristo está presente na Eucaristia dum modo único e incomparável. De facto, está presente de modo verdadeiro, real, substancial: com o seu Corpo e o seu Sangue, com a sua Alma e a sua Divindade. Nela está presente em modo sacramental, isto é, sob as espécies eucarísticas do pão e do vinho, Cristo completo: Deus e homem." },
                new() { Titulo = "283. Que significa transubstanciação?", Texto = "Transubstanciação significa a conversão de toda a substância do pão na substância do Corpo de Cristo e de toda a substância do vinho na substância do seu Sangue. Esta conversão realiza-se na oração eucarística mediante a eficácia da palavra de Cristo e a acção do Espírito Santo. Todavia as características sensíveis do pão e do vinho, isto é as «espécies eucarísticas», permanecem inalteradas." },
                new() { Titulo = "284. A fracção do pão divide Cristo?", Texto = "A fracção do pão não divide Cristo: Ele está presente todo inteiro em cada uma das espécies eucarísticas e em cada uma das suas partes." },
                new() { Titulo = "285. Até quando continua a presença eucarística de Cristo?", Texto = "Ela continua enquanto subsistem as espécies eucarísticas." },
                new() { Titulo = "286. Que tipo de culto é devido ao sacramento da Eucaristia?", Texto = "É devido o culto de latria, isto é, de adoração reservado só a Deus quer durante a celebração eucarística quer fora dela. De facto, a Igreja conserva com a maior diligência as Hóstias consagradas, leva-as aos enfermos, apresenta-as à solene adoração dos fiéis, leva-as em procissão e convida à visita frequente e à adoração do Santíssimo Sacramento conservado no tabernáculo." },
                new() { Titulo = "287. Porque é que a Eucaristia é banquete pascal?", Texto = "A Eucaristia é o banquete pascal, porque Cristo, pela realização sacramental da sua Páscoa, nos dá o seu Corpo e o seu Sangue, oferecidos como alimento e bebida, e nos une a si e entre nós no seu sacrifício." },
                new() { Titulo = "288. Que significa o altar?", Texto = "O altar é o símbolo do próprio Cristo, presente como vítima sacrificial (altar-sacrifício da cruz) e como alimento celeste que se nos dá (altar-mesa eucarística)." },
                new() { Titulo = "289. Quando é que a Igreja obriga a participar na santa Missa?", Texto = "A Igreja obriga os fiéis a participar na santa Missa cada Domingo e nas festas de preceito, e recomenda a participação nela também nos outros dias." },
                new() { Titulo = "290. Quando se deve comungar?", Texto = "A Igreja recomenda aos fiéis que participam na santa Missa que também recebam, com as devidas disposições, a sagrada Comunhão, prescrevendo a obrigação de a receber ao menos pela Páscoa." },
                new() { Titulo = "291. O que se requer para receber a sagrada Comunhão?", Texto = "Para receber a sagrada Comunhão é preciso estar plenamente incorporado à Igreja católica e em estado de graça, isto é, sem consciência de pecado mortal. Quem tem consciência de ter cometido pecado grave deve receber o sacramento da Reconciliação antes da Comunhão. São também importantes o espírito de recolhimento e de oração, a observância do jejum prescrito pela Igreja e a atitude corporal (gestos, trajes), como sinal de respeito para com Cristo." },
                new() { Titulo = "292. Quais são os frutos da sagrada Comunhão?", Texto = "A sagrada Comunhão aumenta a nossa união com Cristo e com a sua Igreja, conserva e renova a vida da graça recebida no Baptismo e no Crisma, e faz-nos crescer no amor para com o próximo. Fortalecendo-nos na caridade, perdoa os pecados veniais e preserva-nos dos pecados mortais, no futuro." },
                new() { Titulo = "293. Quando é possível administrar a sagrada Comunhão aos outros cristãos?", Texto = "Os ministros católicos administram licitamente a sagrada comunhão aos membros das Igrejas orientais que não têm plena comunhão com a Igreja católica, sempre que estes espontaneamente a peçam e com as devidas disposições. No que se refere aos membros doutras Comunidades eclesiais, os ministros católicos administram licitamente a sagrada comunhão aos fiéis que, por motivos graves, a peçam espontaneamente, tenham as devidas disposições e manifestem a fé católica acerca do sacramento." },
                new() { Titulo = "294. Porque é que a Eucaristia é «penhor da futura glória»?", Texto = "Porque a Eucaristia nos enche das graças e bênçãos do Céu, fortalece-nos para a peregrinação desta vida, faz-nos desejar a vida eterna, unindo-nos desde já a Cristo, sentado à direita do Pai, à Igreja do Céu, à santíssima Virgem e a todos os santos." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "O Sacramento da Penitência e da Reconciliação",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "295. Porque é que Cristo instituiu os sacramentos da Penitência e da Unção dos enfermos?", Texto = "Cristo, médico da alma e do corpo, instituiu-os porque a vida nova, que Ele nos deu nos sacramentos da iniciação cristã, pode ser enfraquecida e até perdida por causa do pecado. Por isso, Cristo quis que a Igreja continuasse a sua obra de cura e de salvação mediante estes dois sacramentos." },
                new() { Titulo = "296. Como é chamado este sacramento?", Texto = "É chamado sacramento da Penitência, da Reconciliação, do Perdão, da Confissão, da Conversão." },
                new() { Titulo = "297. Porque existe um sacramento da Reconciliação depois do Baptismo?", Texto = "Porque a nova vida da graça, recebida no Baptismo, não suprimiu a fragilidade da natureza humana nem a inclinação para o pecado (isto é, a concupiscência), Cristo instituiu este sacramento para a conversão dos baptizados que pelo pecado d'Ele se afastaram." },
                new() { Titulo = "298. Quando foi instituído este sacramento?", Texto = "O Senhor ressuscitado instituiu este sacramento quando, na tarde de Páscoa, se mostrou aos Apóstolos e lhes disse: «Recebei o Espírito Santo; àqueles a quem perdoardes os pecados serão perdoados, e àqueles a quem os retiverdes serão retidos» (Jo 20,22-23)." },
                new() { Titulo = "299. Os baptizados têm ainda necessidade de conversão?", Texto = "O apelo à conversão ressoa continuamente na vida dos baptizados. Esta conversão é um empenho contínuo para toda a Igreja, que é santa mas contém pecadores no seu seio." },
                new() { Titulo = "300. O que é a penitência interior?", Texto = "É o dinamismo do «coração contrito» (Sal 51,19), movido pela graça divina a responder ao amor misericordioso de Deus. Implica a dor e a repulsa pelos pecados cometidos, o propósito firme de não mais pecar e a confiança na ajuda de Deus. Alimenta-se da esperança na misericórdia divina." },
                new() { Titulo = "301. Como se manifesta a penitência na vida cristã?", Texto = "A penitência manifesta-se de muitas maneiras, em especial pelo jejum, a oração e a esmola. Estas e muitas outras formas de penitência podem ser praticadas na vida quotidiana do cristão, especialmente no tempo da Quaresma e no dia penitencial de Sexta-feira." },
                new() { Titulo = "302. Quais os elementos essenciais do sacramento da Reconciliação?", Texto = "São dois: os actos realizados pelo homem que se converte sob a acção do Espírito Santo e a absolvição do sacerdote, que em Nome de Cristo concede o perdão e estabelece a modalidade da satisfação." },
                new() { Titulo = "303. Quais são os actos do penitente?", Texto = "São: um diligente exame de consciência; a contrição (ou arrependimento), que é perfeita quando é motivada pelo amor a Deus, e imperfeita se fundada sobre outros motivos, e que inclui o propósito de não mais pecar; a confissão, que consiste na acusação dos pecados feita diante do sacerdote; a satisfação, ou seja, o cumprimento de certos actos de penitência que o confessor impõe ao penitente para reparar o dano causado pelo pecado." },
                new() { Titulo = "304. Que pecados se devem confessar?", Texto = "Devem-se confessar todos os pecados graves ainda não confessados, dos quais nos recordamos depois dum diligente exame de consciência. A confissão dos pecados graves é o único modo ordinário para obter o perdão." },
                new() { Titulo = "305. Quando se é obrigado a confessar os pecados graves?", Texto = "Todo o fiel, obtida a idade da razão, é obrigado a confessar os seus pecados graves ao menos uma vez por ano e antes de receber a Sagrada Comunhão." },
                new() { Titulo = "306. Porque é que os pecados veniais podem ser também objecto da confissão sacramental?", Texto = "A confissão dos pecados veniais é muito recomendada pela Igreja, embora não estritamente necessária, porque nos ajuda a formar uma consciência recta e a lutar contra as más inclinações, para nos deixarmos curar por Cristo e progredirmos na vida do Espírito." },
                new() { Titulo = "307. Quem é o ministro deste sacramento?", Texto = "Cristo confiou o ministério da reconciliação aos seus Apóstolos, aos Bispos seus sucessores e aos presbíteros seus colaboradores, os quais portanto se convertem em instrumentos da misericórdia e da justiça de Deus. Eles exercem o poder de perdoar os pecados no Nome do Pai e do Filho e do Espírito Santo." },
                new() { Titulo = "308. A quem é reservada a absolvição de alguns pecados?", Texto = "A absolvição de alguns pecados particularmente graves (como os punidos com a excomunhão) é reservada à Sé Apostólica ou ao Bispo do lugar ou aos presbíteros por ele autorizados, embora todo o sacerdote possa absolver de qualquer pecado e excomunhão a quem se encontra em perigo de morte." },
                new() { Titulo = "309. O Confessor é obrigado ao segredo?", Texto = "Dada a delicadeza e a grandeza deste ministério e o respeito devido às pessoas, todo o confessor está obrigado a manter o sigilo sacramental, isto é, o absoluto segredo acerca dos pecados conhecidos em confissão, sem nenhuma excepção e sob penas severíssimas." },
                new() { Titulo = "310. Quais são os efeitos deste sacramento?", Texto = "Os efeitos do sacramento da Penitência são: a reconciliação com Deus e portanto o perdão dos pecados; a reconciliação com a Igreja; a recuperação, se perdida, do estado de graça; a remissão da pena eterna merecida por causa dos pecados mortais e, ao menos em parte, das penas temporais; a paz e a serenidade da consciência, e a consolação do espírito; o acréscimo das forças espirituais para o combate cristão." },
                new() { Titulo = "311. Quando se pode celebrar este sacramento com confissão genérica e absolvição colectiva?", Texto = "Em casos de grave necessidade (como o perigo iminente de morte), pode-se recorrer à celebração comunitária da Reconciliação com confissão genérica e absolvição colectiva, respeitando as normas da Igreja e com o propósito de confessar individualmente os pecados graves no tempo oportuno." },
                new() { Titulo = "312. O que são as indulgências?", Texto = "As indulgências são a remissão diante de Deus da pena temporal devida aos pecados, já perdoados quanto à culpa, que, em determinadas condições, o fiel adquire para si ou para os defuntos mediante o ministério da Igreja, a qual, como dispensadora da redenção, distribui o tesouro dos méritos de Cristo e dos Santos." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "O Sacramento da Unção dos Enfermos",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "313. Como é vivida a doença no Antigo Testamento?", Texto = "No Antigo Testamento, o homem doente experimenta os seus limites e ao mesmo tempo percebe que a doença está ligada misteriosamente ao pecado. Os profetas intuíram que a doença podia ter também um valor redentor em relação aos próprios pecados e aos dos outros. Assim, a doença era vivida perante Deus, da qual o homem implorava a cura." },
                new() { Titulo = "314. Que sentido tem a compaixão de Jesus pelos doentes?", Texto = "A compaixão de Jesus pelos doentes e as numerosas curas de enfermos são um claro sinal de que, com Ele, chegou o Reino de Deus e a vitória sobre o pecado, o sofrimento e a morte. Com a sua paixão e morte, Ele dá um novo sentido ao sofrimento, o qual, se unido ao seu, pode ser meio de purificação e de salvação para nós e para os outros." },
                new() { Titulo = "315. Qual é o comportamento da Igreja em relação aos doentes?", Texto = "A Igreja, tendo recebido do Senhor a ordem de curar os enfermos, procura pô-la em prática com os cuidados para com os doentes, acompanhados da oração de intercessão. Ela possui sobretudo um sacramento específico em favor dos enfermos, instituído pelo próprio Cristo e atestado por São Tiago: «Quem está doente, chame a si os presbíteros da Igreja e rezem por ele, depois de o ter ungido com óleo no nome do Senhor» (Tg 5,14-15)." },
                new() { Titulo = "316. Quem pode receber o sacramento da Unção dos enfermos?", Texto = "Este sacramento pode ser recebido pelo fiel que começa a encontrar-se em perigo de morte por doença ou velhice. O mesmo fiel pode recebê-lo também outras vezes se a doença se agrava ou então no caso doutra doença grave. A celebração deste sacramento, se possível, deve ser precedida pela confissão individual do doente." },
                new() { Titulo = "317. Quem administra este sacramento?", Texto = "Só pode ser administrado pelos sacerdotes (Bispos ou presbíteros)." },
                new() { Titulo = "318. Como se celebra este sacramento?", Texto = "A celebração deste sacramento consiste essencialmente na unção com óleo benzido, se possível, pelo Bispo, na fronte e nas mãos do doente (no rito romano, ou também noutras partes do corpo segundo outros ritos), acompanhada da oração do sacerdote, que implora a graça especial deste sacramento." },
                new() { Titulo = "319. Quais são os efeitos deste sacramento?", Texto = "Ele confere uma graça especial que une mais intimamente o doente à Paixão de Cristo, para o seu bem e de toda a Igreja, dando-lhe conforto, paz, coragem, e também o perdão dos pecados, se o doente não se pode confessar. Este sacramento consente por vezes, se for a vontade de Deus, também a recuperação da saúde física. Em todo o caso, esta Unção prepara o doente para a passagem à Casa do Pai." },
                new() { Titulo = "320. O que é o Viático?", Texto = "É a Eucaristia recebida por aqueles que estão para deixar esta vida terrena e se preparam para a passagem à vida eterna. Recebida no momento da passagem deste mundo ao Pai, a Comunhão do Corpo e Sangue de Cristo morto e ressuscitado é semente de vida eterna e potência de ressurreição." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "O Sacramento da Ordem Sacerdotal",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "321. Quais são os sacramentos ao serviço da comunhão e da missão?", Texto = "Dois sacramentos, a Ordem e o Matrimónio, conferem uma graça especial para uma missão particular na Igreja em ordem à edificação do povo de Deus. Eles contribuem em especial para a comunhão eclesial e para a salvação dos outros." },
                new() { Titulo = "322. O que é o sacramento da Ordem?", Texto = "É o sacramento graças ao qual a missão confiada por Cristo aos seus Apóstolos continua a ser exercida na Igreja, até ao fim dos tempos." },
                new() { Titulo = "323. Porque se chama sacramento da Ordem?", Texto = "Ordem indica um corpo eclesial, do qual se passa a fazer parte, mediante uma especial consagração (Ordenação), a qual, por um particular dom do Espírito Santo, permite exercer um poder sagrado em nome e com a autoridade de Cristo para o serviço do povo de Deus." },
                new() { Titulo = "324. Qual o lugar do sacramento da Ordem no desígnio divino da salvação?", Texto = "Na Antiga Aliança, este sacramento é prefigurado no serviço dos Levitas, no sacerdócio de Aarão e na instituição dos setenta «Anciãos» (Num 11,25). Estas prefigurações encontraram realização em Cristo Jesus, o qual, com o sacrifício da sua cruz, é o «único mediador entre Deus e os homens» (1 Tim 2,5), o Sumo-sacerdote «à maneira de Melquisedec» (Heb 5,10). O único sacerdócio de Cristo é tornado presente pelo sacerdócio ministerial." },
                new() { Titulo = "325. De quantos graus se compõe o sacramento da Ordem?", Texto = "Compõe-se de três graus, que são insubstituíveis para a estrutura orgânica da Igreja: o episcopado, o presbiterado e o diaconado." },
                new() { Titulo = "326. Qual é o efeito da Ordenação episcopal?", Texto = "A Ordenação episcopal confere a plenitude do sacramento da Ordem, faz do Bispo o legítimo sucessor dos Apóstolos, insere-o no Colégio episcopal, partilhando com o Papa e os outros Bispos a solicitude por todas as Igrejas, e confere-lhe a missão de ensinar, santificar e governar." },
                new() { Titulo = "327. Qual é a missão do Bispo na Igreja particular que lhe foi confiada?", Texto = "O Bispo, ao qual é confiada uma Igreja particular, é o princípio visível e o fundamento da unidade dessa Igreja, a favor da qual exerce, como vigário de Cristo, o ministério pastoral, coadjuvado pelos presbíteros e diáconos." },
                new() { Titulo = "328. Qual é o efeito da Ordenação presbiteral?", Texto = "A unção do Espírito assinala o presbítero com um carácter espiritual indelével, configura-o a Cristo sacerdote e torna-o capaz de agir em nome de Cristo Cabeça. Sendo cooperador da Ordem episcopal, ele é consagrado para pregar o Evangelho, para celebrar o culto divino, sobretudo a Eucaristia, da qual o seu ministério recebe a força, e para ser o pastor dos fiéis." },
                new() { Titulo = "329. Como é que o presbítero exerce o seu ministério?", Texto = "Embora seja ordenado para uma missão universal, ele exerce-a numa Igreja particular, em fraternidade sacramental com os outros presbíteros que formam o «presbitério» e que, em comunhão com o Bispo e em dependência dele, têm a responsabilidade da Igreja particular." },
                new() { Titulo = "330. Qual é o efeito da Ordenação diaconal?", Texto = "O diácono, configurado a Cristo servo de todos, é ordenado para o serviço da Igreja sob a autoridade do Bispo, em relação ao ministério da Palavra, do culto divino, da condução pastoral e da caridade." },
                new() { Titulo = "331. Como se celebra o sacramento da Ordem?", Texto = "Para cada um dos três graus, o sacramento da Ordem é conferido pela imposição das mãos sobre a cabeça do ordinando por parte do Bispo, que pronuncia a solene oração consecratória. Com ela, o Bispo invoca de Deus, para o ordinando, a especial efusão do Espírito Santo e dos seus dons, em ordem ao ministério." },
                new() { Titulo = "332. Quem pode conferir este sacramento?", Texto = "Compete aos Bispos validamente ordenados, enquanto sucessores dos Apóstolos, conferir os três graus do sacramento da Ordem." },
                new() { Titulo = "333. Quem pode receber este sacramento?", Texto = "Só o baptizado de sexo masculino o pode receber validamente: a Igreja reconhece-se vinculada a esta escolha feita pelo próprio Senhor. Ninguém pode exigir a recepção do sacramento da Ordem, antes deve ser considerado apto para o ministério pela autoridade da Igreja." },
                new() { Titulo = "334. É requerido o celibato a quem recebe o sacramento da Ordem?", Texto = "Para o episcopado é sempre requerido o celibato. Na Igreja latina, para o presbiterado, são normalmente escolhidos homens crentes que vivem celibatários e têm vontade de guardar o celibato «pelo reino dos céus» (Mt 19,12). Nas Igrejas Orientais, não é consentido casar depois da Ordenação. O diaconado permanente pode ser conferido a homens já casados." },
                new() { Titulo = "335. Quais são os efeitos do sacramento da Ordem?", Texto = "Este sacramento dá uma especial efusão do Espírito Santo, que configura o ordenado a Cristo na sua tríplice função de Sacerdote, Profeta e Rei, segundo os respectivos graus do sacramento. A ordenação confere um carácter espiritual indelével: por isso não pode ser repetida nem conferida por um tempo limitado." },
                new() { Titulo = "336. Com que autoridade é exercido o sacerdócio ministerial?", Texto = "Os sacerdotes ordenados, no exercício do ministério sagrado, falam e agem não por autoridade própria, e nem sequer por mandato ou delegação da comunidade, mas na Pessoa de Cristo Cabeça e em nome da Igreja. Portanto o sacerdócio ministerial difere essencialmente, e não apenas em grau, do sacerdócio comum dos fiéis, para o serviço do qual Cristo o instituiu." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "O Sacramento do Matrimónio",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "337. Qual é o desígnio de Deus acerca do homem e da mulher?", Texto = "Deus, que é amor e criou o homem por amor, chamou-o a amar. Criando o homem e a mulher, chamou-os, no Matrimónio, a uma íntima comunhão de vida e de amor entre eles, «de modo que já não são dois, mas uma só carne» (Mt 19,6). Abençoando-os, Deus disse-lhes: «sede fecundos e multiplicai-vos» (Gn 1,28)." },
                new() { Titulo = "338. Para que fins instituiu Deus o Matrimónio?", Texto = "A união matrimonial do homem e da mulher, fundada e dotada de leis próprias pelo Criador, está por sua natureza ordenada à comunhão e ao bem dos cônjuges e à geração e bem dos filhos. Segundo o desígnio originário de Deus, a união matrimonial é indissolúvel, como afirma Jesus Cristo: «O que Deus uniu não o separe o homem» (Mc 10,9)." },
                new() { Titulo = "339. Como é que o pecado ameaça o Matrimónio?", Texto = "Por causa do primeiro pecado, que provocou também a ruptura da comunhão do homem e da mulher dada pelo Criador, a união matrimonial é muitas vezes ameaçada pela discórdia e pela infidelidade. Todavia Deus, na sua infinita misericórdia, dá ao homem e à mulher a sua graça para que possam realizar a união das suas vidas segundo o desígnio originário de Deus." },
                new() { Titulo = "340. O que é que o Antigo Testamento ensina sobre o Matrimónio?", Texto = "Deus, sobretudo através da pedagogia da Lei e dos profetas, ajuda o seu povo a amadurecer progressivamente a consciência da unicidade e da indissolubilidade do Matrimónio. A aliança nupcial de Deus com Israel prepara e prefigura a Aliança nova realizada pelo Filho de Deus com a sua esposa, a Igreja." },
                new() { Titulo = "341. Qual a novidade dada por Cristo ao Matrimónio?", Texto = "Jesus Cristo não só restabelece a ordem inicial querida por Deus, mas dá a graça para viver o Matrimónio na nova dignidade de sacramento, que é o sinal do seu amor esponsal pela Igreja: «Vós maridos amai as vossas mulheres, como Cristo amou a Igreja» (Ef 5,25)." },
                new() { Titulo = "342. O Matrimónio é uma obrigação para todos?", Texto = "O Matrimónio não é uma obrigação para todos. Deus chama alguns homens e mulheres a seguir o Senhor Jesus na vida da virgindade ou do celibato pelo Reino dos céus, renunciando ao grande bem do Matrimónio para se preocuparem com as coisas do Senhor e tornando-se assim sinal do absoluto primado do amor de Cristo e da ardente esperança da sua vinda gloriosa." },
                new() { Titulo = "343. Como se celebra o sacramento do Matrimónio?", Texto = "Uma vez que o Matrimónio coloca os cônjuges num estado público de vida na Igreja, a sua celebração litúrgica é pública, na presença do sacerdote (ou da testemunha qualificada da Igreja) e das outras testemunhas." },
                new() { Titulo = "344. O que é o consentimento matrimonial?", Texto = "O consentimento matrimonial é a vontade, expressa por um homem e por uma mulher, de se entregarem mutua e definitivamente, com o fim de viver uma aliança de amor fiel e fecundo. Dado que o consentimento faz o Matrimónio, ele é indispensável e insubstituível. Para que o Matrimónio seja válido, o consentimento deve ter como objecto o verdadeiro Matrimónio e ser um acto humano, consciente e livre, não determinado pela violência ou por constrições." },
                new() { Titulo = "345. Que se requer quando um dos esposos não é católico?", Texto = "Para serem lícitos, os matrimónios mistos (entre católico e baptizado não católico) requerem a permissão da autoridade eclesiástica. Aqueles com disparidade de culto (entre católico e não baptizado) para serem válidos precisam duma dispensa. Em todo o caso, é essencial que os cônjuges não excluam a aceitação dos fins e das propriedades essenciais do Matrimónio e que o cônjuge católico confirme o empenho de conservar a fé e de assegurar o Baptismo e a educação católica dos filhos." },
                new() { Titulo = "346. Quais são os efeitos do sacramento do Matrimónio?", Texto = "O sacramento do Matrimónio gera entre os cônjuges um vínculo perpétuo e exclusivo. O próprio Deus sela o consentimento dos esposos. Portanto o Matrimónio concluído e consumado entre baptizados não pode ser nunca dissolvido. Este sacramento confere também aos esposos a graça necessária para alcançar a santidade na vida conjugal e para o acolhimento responsável dos filhos e a sua educação." },
                new() { Titulo = "347. Quais são os pecados gravemente contrários ao sacramento do Matrimónio?", Texto = "São: o adultério; a poligamia, porque em contradição com a igual dignidade do homem e da mulher e com a unicidade e exclusividade do amor conjugal; a rejeição da fecundidade, que priva a vida conjugal do dom dos filhos; e o divórcio, que se opõe à indissolubilidade." },
                new() { Titulo = "348. Quando é que a Igreja admite a separação física dos esposos?", Texto = "A Igreja admite a separação física dos esposos quando, por motivos graves, a sua coabitação se tornou praticamente impossível, embora se deseje uma sua reconciliação. Mas eles, enquanto vive o cônjuge, não estão livres para contrair uma nova união, a menos que o Matrimónio seja nulo e como tal seja declarado pela autoridade eclesiástica." },
                new() { Titulo = "349. Qual é a atitude da Igreja para com os divorciados recasados?", Texto = "Fiel ao Senhor, a Igreja não pode reconhecer como Matrimónio a união dos divorciados recasados civilmente. «Quem repudia a própria mulher e casa com outra comete adultério contra ela; se a mulher repudia o marido e casa com outro, comete adultério» (Mc 10,11-12). Para com eles, a Igreja desenvolve uma atenta solicitude, convidando-os a uma vida de fé, à oração, às obras de caridade e à educação cristã dos filhos. Mas eles não podem receber a absolvição sacramental nem acercar-se da comunhão eucarística, nem exercer certas responsabilidades eclesiais, enquanto perdurar esta situação que objectivamente contrasta com a lei de Deus." },
                new() { Titulo = "350. Porque é que a família cristã é chamada Igreja doméstica?", Texto = "Porque a família manifesta e realiza a natureza de comunhão e familiar da Igreja como família de Deus. Cada membro, a seu modo, exerce o sacerdócio baptismal, contribuindo para fazer da família uma comunidade de graça e de oração, escola das virtudes humanas e cristãs, lugar do primeiro anúncio da fé aos filhos." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "Os Sacramentais e as Exéquias Cristãs",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "351. O que são os sacramentais?", Texto = "São sinais sagrados instituídos pela Igreja, por meio dos quais são santificadas algumas circunstâncias da vida. Incluem sempre uma oração, muitas vezes acompanhada do sinal da cruz e de outros sinais. Entre os sacramentais, figuram, em primeiro lugar, as bênçãos, que são um louvor a Deus e uma oração para obter os seus dons, as consagrações de pessoas e as dedicações de coisas para o culto de Deus." },
                new() { Titulo = "352. O que é o exorcismo?", Texto = "Fala-se de exorcismo, quando a Igreja pede com a sua autoridade, em nome de Jesus, que uma pessoa ou um objecto seja protegido contra a acção do Maligno e subtraído ao seu domínio. É praticado de modo ordinário no rito do Baptismo. O exorcismo solene, chamado o grande exorcismo, pode ser feito só por um sacerdote autorizado pelo Bispo." },
                new() { Titulo = "353. Que formas de piedade popular acompanham a vida sacramental da Igreja?", Texto = "O sentido religioso do povo cristão encontrou sempre diversas expressões nas várias formas de piedade que acompanham a vida sacramental da Igreja, como a veneração das relíquias, as visitas aos santuários, as peregrinações, as procissões, a «via-sacra», o Rosário. As formas autênticas de piedade popular são favorecidas e iluminadas pela luz da fé da Igreja." },
                new() { Titulo = "354. Que relação existe entre os sacramentais e a morte do cristão?", Texto = "O cristão que morre em Cristo chega, no termo da sua existência terrena, à consumação da nova vida iniciada com o Baptismo, revigorada pela Confirmação e alimentada pela Eucaristia, antecipação do banquete celeste. O sentido da morte do cristão manifesta-se à luz da Morte e da Ressurreição de Cristo, nossa única esperança." },
                new() { Titulo = "355. O que exprimem as exéquias?", Texto = "As exéquias, embora celebradas segundo diferentes ritos correspondentes às situações e às tradições de cada uma das regiões, exprimem o carácter pascal da morte cristã na esperança da ressurreição e o sentido da comunhão com o defunto, particularmente mediante a oração pela purificação da sua alma." },
                new() { Titulo = "356. Quais os momentos principais das exéquias?", Texto = "Habitualmente as exéquias compreendem quatro momentos principais: o acolhimento da urna pela comunidade, com palavras de conforto e de esperança; a liturgia da Palavra; o sacrifício eucarístico; e «a encomendação», com o qual a alma do defunto é confiada a Deus, fonte de vida eterna, enquanto o seu corpo é sepultado na expectativa da ressurreição." },
            }
        },

        // ─────────────────────────────────────────────────────────────────────
        // TERCEIRA PARTE: A VIDA EM CRISTO
        // ─────────────────────────────────────────────────────────────────────

        new CatecismoPtTopico
        {
            Titulo = "A Dignidade da Pessoa Humana",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "357. Como é que a vida moral cristã está ligada à fé e aos sacramentos?", Texto = "O que o Símbolo da fé professa, os sacramentos o comunicam. De facto, neles os fiéis recebem a graça de Cristo e os dons do Espírito Santo, que os tornam capazes de viver a vida nova de filhos de Deus em Cristo acolhido com a fé." },
                new() { Titulo = "358. Qual é a raiz da dignidade humana?", Texto = "A dignidade da pessoa humana radica na criação à imagem e semelhança de Deus. Dotada de uma alma espiritual e imortal, de inteligência e de vontade livre, a pessoa humana está ordenada para Deus e chamada, com a sua alma e o seu corpo, à bem-aventurança eterna." },
                new() { Titulo = "359. Como é que o homem alcança a bem-aventurança?", Texto = "O homem alcança a bem-aventurança em virtude da graça de Cristo, que o torna participante da vida divina. Cristo no Evangelho indica aos seus o caminho que conduz à felicidade sem fim: as Bem-aventuranças. A graça de Cristo opera também em cada ser humano que, seguindo a recta consciência, procura e ama o verdadeiro e o bem e evita o mal." },
                new() { Titulo = "360. Porque é que as Bem-aventuranças são importantes para nós?", Texto = "As Bem-aventuranças estão no centro da pregação de Jesus, retomam e aperfeiçoam as promessas de Deus, feitas a partir de Abraão. Mostram o próprio rosto de Jesus, caracterizam a autêntica vida cristã e revelam ao homem o fim último do seu agir: a bem-aventurança eterna." },
                new() { Titulo = "361. Que relação há entre as Bem-aventuranças e o desejo humano de felicidade?", Texto = "As Bem-aventuranças respondem ao desejo inato de felicidade que Deus colocou no coração do homem para o atrair a Si, e que só Ele pode saciar." },
                new() { Titulo = "362. O que é a bem-aventurança eterna?", Texto = "É a visão de Deus na vida eterna, em que seremos plenamente «participantes da natureza divina» (2 Ped 1,4), da glória de Cristo e da felicidade da vida trinitária. A bem-aventurança ultrapassa as capacidades humanas: é um dom sobrenatural e gratuito de Deus, como a graça que a ela conduz. A bem-aventurança prometida coloca-nos perante escolhas morais decisivas em relação aos bens terrenos, estimulando-nos a amar a Deus acima de tudo." },
                new() { Titulo = "363. O que é a liberdade?", Texto = "É o poder, dado por Deus ao homem, de agir e não agir, de fazer isto ou aquilo, praticando assim por si mesmo acções deliberadas. A liberdade caracteriza os actos propriamente humanos. Quanto mais faz o bem, mais alguém se torna livre. A liberdade atinge a perfeição quando é ordenada para Deus, sumo Bem e nossa Bem-aventurança. A liberdade implica também a possibilidade de escolher entre o bem e o mal. A escolha do mal é um abuso da liberdade, que conduz à escravatura do pecado." },
                new() { Titulo = "364. Que relação existe entre liberdade e responsabilidade?", Texto = "A liberdade torna o homem responsável pelos seus actos, na medida em que são voluntários, embora a imputabilidade e a responsabilidade de um acto possam ser diminuídas, e até anuladas, pela ignorância, a inadvertência, a violência suportada, o medo, as afeições desordenadas e os hábitos." },
                new() { Titulo = "365. Porque é que o homem tem direito ao exercício da liberdade?", Texto = "O direito ao exercício da liberdade é próprio de cada homem enquanto é inseparável da sua dignidade de pessoa humana. Portanto, tal direito deve ser sempre respeitado, principalmente em matéria moral e religiosa, e deve ser reconhecido civilmente e tutelado nos termos do bem comum e da justa ordem pública." },
                new() { Titulo = "366. Qual é o lugar da liberdade humana na ordem da salvação?", Texto = "O primeiro pecado enfraqueceu a liberdade humana. Os pecados sucessivos vieram acentuar esta debilidade. Mas «foi para a liberdade que Cristo nos libertou» (Gal 5,1). Com a sua graça, o Espírito Santo conduz-nos para a liberdade espiritual, para fazer de nós colaboradores livres da sua obra na Igreja e no mundo." },
                new() { Titulo = "367. Quais são as fontes da moralidade dos actos humanos?", Texto = "A moralidade dos actos humanos depende de três fontes: do objecto escolhido, ou seja, dum bem verdadeiro ou aparente; da intenção do sujeito que age, isto é, do fim que ele tem em vista ao fazer a acção; das circunstâncias da acção, onde se incluem as suas consequências." },
                new() { Titulo = "368. Quando é que o acto é moralmente bom?", Texto = "O acto é moralmente bom quando supõe, ao mesmo tempo, a bondade do objecto, do fim em vista e das circunstâncias. O objecto escolhido pode, por si só, viciar toda a acção, mesmo se a sua intenção for boa. Não é lícito fazer o mal para que dele derive um bem. Um fim mau pode corromper a acção, mesmo que, em si, o seu objecto seja bom. Pelo contrário, um fim bom não torna bom um comportamento que for mau pelo seu objecto, uma vez que o fim não justifica os meios." },
                new() { Titulo = "369. Há actos que são sempre ilícitos?", Texto = "Há actos, cuja escolha é sempre ilícita, por causa do seu objecto (por exemplo, a blasfémia, o homicídio, o adultério). A sua escolha comporta uma desordem da vontade, isto é, um mal moral, que não pode ser justificado com os bens que eventualmente daí pudessem derivar." },
                new() { Titulo = "370. O que são as paixões?", Texto = "São os afectos, as emoções ou os movimentos da sensibilidade — componentes naturais da psicologia humana — que inclinam a agir ou a não agir em vista do que se percebeu como bom ou como mau. As principais são o amor e o ódio, o desejo e o medo, a alegria, a tristeza e a cólera. A paixão fundamental é o amor, provocado pela atracção do bem." },
                new() { Titulo = "371. As paixões são moralmente boas ou más?", Texto = "Enquanto movimentos da sensibilidade, as paixões não são nem boas nem más em si mesmas: são boas quando contribuem para uma acção boa; são más, no caso contrário. Elas podem ser assumidas pelas virtudes ou pervertidas nos vícios." },
                new() { Titulo = "372. O que é a consciência moral?", Texto = "A consciência moral, presente no íntimo da pessoa, é um juízo da razão, que, no momento oportuno, ordena ao homem que pratique o bem e evite o mal. Graças a ela, a pessoa humana percebe a qualidade moral dum acto a realizar ou já realizado, permitindo-lhe assumir a responsabilidade. Quando escuta a consciência moral, o homem prudente pode ouvir a voz de Deus que lhe fala." },
                new() { Titulo = "373. Que implica a dignidade da pessoa perante a consciência moral?", Texto = "A dignidade da pessoa humana implica rectidão da consciência moral (ou seja, estar de acordo com o que é justo e bom, segundo a razão e a Lei divina). Por causa da sua dignidade pessoal, o homem não deve ser obrigado a agir contra a consciência e, dentro dos limites do bem comum, nem sequer deve ser impedido de agir em conformidade com ela, sobretudo em matéria religiosa." },
                new() { Titulo = "374. Como formar a recta e verdadeira consciência moral?", Texto = "A consciência moral recta e verdadeira forma-se com a educação e com a assimilação da Palavra de Deus e do ensino da Igreja. É amparada com os dons do Espírito Santo e ajudada com os conselhos de pessoas sábias. Além disso, ajudam muito na formação moral a oração e o exame de consciência." },
                new() { Titulo = "375. Quais as normas que a consciência deve sempre seguir?", Texto = "Há três mais gerais: 1) nunca é permitido fazer o mal porque daí derive um bem; 2) a chamada regra de ouro: «tudo quanto quiserdes que os homens vos façam, fazei-lho vós também» (Mt 7,12); 3) a caridade passa sempre pelo respeito do próximo e da sua consciência, embora isto não signifique aceitar como um bem aquilo que é objectivamente um mal." },
                new() { Titulo = "376. A consciência moral pode emitir juízos erróneos?", Texto = "A pessoa deve obedecer sempre ao juízo certo da sua consciência, mas esta também pode emitir juízos erróneos, por causas nem sempre isentas de culpabilidade pessoal. Não é porém imputável à pessoa o mal realizado por ignorância involuntária, mesmo que objectivamente não deixe de ser um mal. É preciso, pois, trabalhar para corrigir os erros da consciência moral." },
                new() { Titulo = "377. O que é a virtude?", Texto = "A virtude é uma disposição habitual e firme para fazer o bem. «O fim de uma vida virtuosa é tornar-se semelhante a Deus» (S. Gregório de Nissa). Há virtudes humanas e virtudes teologais." },
                new() { Titulo = "378. O que são as virtudes humanas?", Texto = "As virtudes humanas são perfeições habituais e estáveis da inteligência e da vontade, que regulam os nossos actos, ordenam as nossas paixões e guiam a nossa conduta segundo a razão e a fé. Adquiridas e reforçadas por actos moralmente bons e repetidos, são purificadas e elevadas pela graça divina." },
                new() { Titulo = "379. Quais são as virtudes humanas principais?", Texto = "São as virtudes, chamadas cardeais, que reagrupam todas as outras e que constituem a charneira da vida virtuosa. São elas: prudência, justiça, fortaleza e temperança." },
                new() { Titulo = "380. O que é a prudência?", Texto = "A prudência dispõe a razão para discernir em todas as circunstâncias o nosso verdadeiro bem e a escolher os justos meios para o atingir. Ela conduz as outras virtudes, indicando-lhes a regra e a medida." },
                new() { Titulo = "381. O que é a justiça?", Texto = "A justiça consiste na constante e firme vontade de dar aos outros o que lhes é devido. A justiça para com Deus é chamada «virtude da religião»." },
                new() { Titulo = "382. O que é a fortaleza?", Texto = "A fortaleza assegura a firmeza nas dificuldades e a constância na procura do bem, chegando até à capacidade do eventual sacrifício da própria vida por uma causa justa." },
                new() { Titulo = "383. O que é a temperança?", Texto = "A temperança modera a atracção dos prazeres, assegura o domínio da vontade sobre os instintos e proporciona o equilíbrio no uso dos bens criados." },
                new() { Titulo = "384. O que são as virtudes teologais?", Texto = "São as virtudes que têm como origem, motivo e objecto imediato o próprio Deus. São infundidas no homem com a graça santificante, tornam-nos capazes de viver em relação com a Trindade e fundamentam e animam o agir moral do cristão, vivificando as virtudes humanas. Elas são o penhor da presença e da acção do Espírito Santo nas faculdades do ser humano." },
                new() { Titulo = "385. Quais são as virtudes teologais?", Texto = "As virtudes teologais são: fé, esperança e caridade." },
                new() { Titulo = "386. O que é a fé?", Texto = "A fé é a virtude teologal pela qual cremos em Deus e em tudo o que Ele nos revelou e que a Igreja nos propõe para acreditarmos, porque Ele é a própria Verdade. Pela fé, o homem entrega-se a Deus livremente. Por isso, o crente procura conhecer e fazer a vontade de Deus, porque «a fé opera pela caridade» (Gal 5,6)." },
                new() { Titulo = "387. O que é a esperança?", Texto = "A esperança é a virtude teologal por meio da qual desejamos e esperamos de Deus a vida eterna como nossa felicidade, colocando a nossa confiança nas promessas de Cristo e apoiando-nos na ajuda da graça do Espírito Santo para merecê-la e perseverar até ao fim da vida terrena." },
                new() { Titulo = "388. O que é a caridade?", Texto = "A caridade é a virtude teologal pela qual amamos a Deus sobre todas as coisas e ao próximo como a nós mesmos por amor de Deus. Jesus faz dela o mandamento novo, a plenitude da lei. A caridade é «o vínculo da perfeição» (Col 3,14) e o fundamento das outras virtudes, que ela anima, inspira e ordena: sem ela «não sou nada» e «nada me aproveita» (1 Cor 13,1-3)." },
                new() { Titulo = "389. O que são os dons do Espírito Santo?", Texto = "Os dons do Espírito Santo são disposições permanentes que tornam o homem dócil para seguir as inspirações divinas. São sete: sabedoria, entendimento, conselho, fortaleza, ciência, piedade e temor de Deus." },
                new() { Titulo = "390. O que são os frutos do Espírito Santo?", Texto = "Os frutos do Espírito Santo são perfeições plasmadas por Ele em nós como primícias da glória eterna. A tradição da Igreja enumera doze: «Amor, alegria, paz, paciência, longanimidade, bondade, benignidade, mansidão, fidelidade, modéstia, continência, castidade» (Gal 5,22-23 vulgata)." },
                new() { Titulo = "391. O que exige de nós o acolhimento da misericórdia de Deus?", Texto = "Exige o reconhecimento das nossas culpas e o arrependimento dos nossos pecados. Pela sua Palavra e pelo seu Espírito, o próprio Deus nos revela os nossos pecados, dá-nos a verdade da consciência e a esperança do perdão." },
                new() { Titulo = "392. O que é o pecado?", Texto = "É «uma palavra, um acto ou um desejo contrários à Lei eterna» (S. Agostinho). É uma ofensa a Deus, na desobediência ao seu amor. Fere a natureza do homem e atenta contra a solidariedade humana. Cristo, na sua Paixão, revela plenamente a gravidade do pecado e vence-o com a sua misericórdia." },
                new() { Titulo = "393. Existe uma variedade de pecados?", Texto = "A variedade dos pecados é grande. Distinguem-se segundo o seu objecto, ou segundo as virtudes ou os mandamentos a que se opõem. Podem ser directamente contra Deus, contra o próximo e contra nós mesmos. Podemos ainda distinguir entre pecados por pensamentos, por palavras, por acções e por omissões." },
                new() { Titulo = "394. Como se distingue o pecado quanto à gravidade?", Texto = "Distingue-se entre pecado mortal e venial." },
                new() { Titulo = "395. Quando se comete o pecado mortal?", Texto = "Comete-se pecado mortal quando, ao mesmo tempo, há matéria grave, plena consciência e deliberado consentimento. Este pecado destrói a caridade, priva-nos da graça santificante e conduz-nos à morte eterna do inferno, se dele não nos arrependermos. É perdoado ordinariamente mediante os sacramentos do Baptismo e da Penitência ou Reconciliação." },
                new() { Titulo = "396. Quando se comete o pecado venial?", Texto = "O pecado venial, que difere essencialmente do pecado mortal, comete-se quando se trata de matéria leve, ou mesmo grave, mas sem pleno conhecimento ou sem total consentimento. Não quebra a aliança com Deus, mas enfraquece a caridade; manifesta um afecto desordenado pelos bens criados; impede o progresso da alma no exercício das virtudes e na prática do bem moral; merece penas purificatórias temporais." },
                new() { Titulo = "397. Como prolifera em nós o pecado?", Texto = "O pecado arrasta ao pecado e a sua repetição gera o vício." },
                new() { Titulo = "398. O que são os vícios?", Texto = "Os vícios, sendo contrários às virtudes, são hábitos perversos que obscurecem a consciência e inclinam ao mal. Os vícios podem estar ligados aos chamados sete pecados capitais, que são: soberba, avareza, inveja, ira, luxúria, gula e preguiça ou negligência." },
                new() { Titulo = "399. Temos responsabilidade nos pecados cometidos por outros?", Texto = "Existe esta responsabilidade, quando culpavelmente neles cooperamos." },
                new() { Titulo = "400. O que são as estruturas de pecado?", Texto = "São situações sociais ou instituições contrárias à lei divina, expressão e efeito de pecados pessoais." },
            }
        },

        // ─────────────────────────────────────────────────────────────────────
        // TERCEIRA PARTE — SECÇÃO 1, CAP. 2
        // ─────────────────────────────────────────────────────────────────────

        new CatecismoPtTopico
        {
            Titulo = "A Comunidade Humana",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "401. Em que consiste a dimensão social do homem?", Texto = "Juntamente com o chamamento pessoal à bem-aventurança, o homem tem a dimensão social como componente essencial da sua natureza e da sua vocação. De facto, todos os homens são chamados ao mesmo fim, que é o próprio Deus; existe uma certa semelhança entre a comunhão das Pessoas divinas e a fraternidade que os homens devem instaurar entre si na verdade e na caridade; o amor ao próximo é inseparável do amor a Deus." },
                new() { Titulo = "402. Qual é a relação entre pessoa e sociedade?", Texto = "Princípio, sujeito e fim de todas as instituições sociais é e deve ser a pessoa. Certas sociedades, como a família e a sociedade civil, são necessárias para ela. São úteis ainda outras associações, tanto no interior das comunidades políticas como a nível internacional, no respeito do princípio de subsidiariedade." },
                new() { Titulo = "403. O que indica o princípio de subsidiariedade?", Texto = "Este princípio indica que uma sociedade de ordem superior não deve assumir uma tarefa que diga respeito a uma sociedade de ordem inferior, privando-a das suas competências, mas deve, antes, apoiá-la em caso de necessidade." },
                new() { Titulo = "404. Que outras coisas requer uma autêntica convivência humana?", Texto = "Requer o respeito da justiça, a justa hierarquia de valores e a subordinação das dimensões materiais e instintivas às superiores e espirituais. Em especial, onde o pecado perverte o clima social, é necessário apelar à conversão dos corações e à graça de Deus, para obter mudanças sociais que estejam realmente ao serviço de cada pessoa e de toda a pessoa. A caridade, que exige e torna capaz da prática da justiça, é o maior mandamento social." },
                new() { Titulo = "405. Em que se funda a autoridade na sociedade?", Texto = "Toda a comunidade humana tem necessidade duma autoridade legítima, que assegure a ordem e contribua para a realização do bem comum. Tal autoridade encontra o seu fundamento na natureza humana, porque corresponde à ordem estabelecida por Deus." },
                new() { Titulo = "406. Quando é que a autoridade é exercida legitimamente?", Texto = "A autoridade é exercida legitimamente quando procura o bem comum e emprega meios moralmente lícitos para o conseguir. Por isso, os regimes políticos devem ser determinados pela decisão livre dos cidadãos e devem respeitar o princípio do «Estado de direito», no qual é soberana a lei e não a vontade arbitrária dos homens. As leis injustas e as medidas contrárias à ordem moral não obrigam as consciências." },
                new() { Titulo = "407. O que é o bem comum?", Texto = "Por bem comum entende-se o conjunto das condições de vida social que permitem aos grupos e aos indivíduos atingir a sua perfeição." },
                new() { Titulo = "408. O que é que comporta o bem comum?", Texto = "O bem comum comporta: o respeito e a promoção dos direitos fundamentais da pessoa; o desenvolvimento dos bens espirituais e temporais das pessoas e da sociedade; a paz e a segurança de todos." },
                new() { Titulo = "409. Onde é que se realiza dum modo mais relevante o bem comum?", Texto = "A realização mais completa do bem comum encontra-se nas comunidades políticas, que defendem e promovem o bem dos cidadãos e dos corpos intermédios, sem esquecer o bem universal da família humana." },
                new() { Titulo = "410. Como é que o homem participa na promoção do bem comum?", Texto = "Cada ser humano, segundo o lugar que ocupa e o papel que desempenha, participa na promoção do bem comum respeitando as leis justas e encarregando-se de sectores de que assume a responsabilidade pessoal, como o cuidado da própria família e o empenho no seu trabalho. Para além disso, os cidadãos, na medida do possível, devem tomar parte activa na vida pública." },
                new() { Titulo = "411. Como é que a sociedade assegura a justiça social?", Texto = "A sociedade assegura a justiça social quando respeita a dignidade e os direitos da pessoa, que constituem o seu próprio fim. Além disso, a sociedade procura a justiça social, que está conexa ao bem comum e ao exercício da autoridade, quando realiza as condições que permitam às associações e ao indivíduo obter aquilo a que têm direito." },
                new() { Titulo = "412. Em que se funda a igualdade entre os homens?", Texto = "Todos os homens gozam de igual dignidade e direitos fundamentais, uma vez que, criados à imagem do Deus único e dotados duma alma racional, têm a mesma natureza e origem e são chamados, em Cristo único salvador, à mesma bem-aventurança divina." },
                new() { Titulo = "413. Como avaliar a desigualdade entre os homens?", Texto = "Há iníquas desigualdades económicas e sociais, que ferem milhões de seres humanos; elas estão em contradição aberta com o Evangelho, são contrárias à justiça, à dignidade das pessoas e à paz. Mas há também diferenças entre os homens, causadas por factores que fazem parte do plano de Deus. Com efeito, Ele quer que cada um receba dos outros aquilo de que precisa, e quer que os que dispõem de «talentos» particulares os partilhem com os outros. Tais diferenças estimulam e obrigam, muitas vezes, as pessoas à magnanimidade, à benevolência e à partilha, e incitam as culturas a enriquecerem-se umas às outras." },
                new() { Titulo = "414. Como se manifesta a solidariedade humana?", Texto = "A solidariedade, exigência da fraternidade humana e cristã, manifesta-se, em primeiro lugar, na justa repartição dos bens, équa na remuneração do trabalho e no esforço por uma ordem social mais justa. A virtude da solidariedade pratica também a repartição dos bens espirituais da fé, ainda mais importantes que os materiais." },
            }
        },

        // ─────────────────────────────────────────────────────────────────────
        // TERCEIRA PARTE — SECÇÃO 1, CAP. 3
        // ─────────────────────────────────────────────────────────────────────

        new CatecismoPtTopico
        {
            Titulo = "A Salvação de Deus: A Lei e a Graça",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "415. O que é a lei moral?", Texto = "A lei moral é obra da Sabedoria divina. Prescreve-nos caminhos e normas de conduta que levam à bem-aventurança prometida, proibindo-nos os caminhos que nos desviam de Deus." },
                new() { Titulo = "416. Em que consiste a lei moral natural?", Texto = "A lei natural, escrita pelo Criador no coração de cada ser humano, consiste numa participação na sabedoria e bondade de Deus, e manifesta o sentido moral originário que permite ao homem discernir, pela razão, o bem e o mal. Ela é universal e imutável, e constitui a base dos deveres e dos direitos fundamentais da pessoa, bem como da comunidade humana e da própria lei civil." },
                new() { Titulo = "417. Esta lei é percebida por todos?", Texto = "Por causa do pecado, a lei natural nem sempre é percebida por todos com igual clareza e imediatez. Por isso Deus «escreveu nas tábuas da Lei o que os homens não conseguiam ler nos seus corações» (S. Agostinho)." },
                new() { Titulo = "418. Qual é a relação entre a Lei Natural e a Antiga Lei?", Texto = "A Antiga Lei é o primeiro estádio da Lei revelada. Ela exprime muitas verdades que são naturalmente acessíveis à razão e que se encontram assim declaradas e autenticadas nas Alianças da salvação. As suas prescrições morais estão compendiadas nos Dez Mandamentos do Decálogo, colocam os alicerces da vocação do homem, proíbem o que é contrário ao amor de Deus e do próximo e prescrevem o que lhe é essencial." },
                new() { Titulo = "419. Qual o lugar da antiga Lei, no plano da salvação?", Texto = "A Antiga Lei permite conhecer muitas verdades acessíveis à razão, indica o que se deve e o que se não deve fazer, e sobretudo, como um sábio pedagogo, prepara e dispõe à conversão e ao acolhimento do Evangelho. Todavia, embora santa, espiritual e boa, a Lei antiga é ainda imperfeita, pois, por si, não dá a força e a graça do Espírito para a cumprir." },
                new() { Titulo = "420. O que é a Nova Lei ou Lei evangélica?", Texto = "A Nova Lei ou Lei evangélica, proclamada e realizada por Cristo, é a perfeição e cumprimento da Lei divina, natural e revelada. Resume-se no mandamento do amor a Deus e ao próximo, e de nos amarmos como Cristo nos amou; é também uma realidade interior dada ao homem: a graça do Espírito Santo que torna possível um tal amor. É a «lei da liberdade» (Tg 1,25), porque nos inclina a agir espontaneamente sob o impulso da caridade. «A Lei nova é sobretudo a própria graça do Espírito Santo, dada aos crentes em Cristo» (S. Tomás de Aquino)." },
                new() { Titulo = "421. Onde se encontra a Lei nova?", Texto = "A Lei nova encontra-se em toda a vida e pregação de Cristo e na catequese moral dos Apóstolos: o Sermão do Senhor na Montanha é a sua principal expressão." },
                new() { Titulo = "422. O que é a justificação?", Texto = "A justificação é a obra mais excelente do amor de Deus. É a acção misericordiosa e gratuita de Deus, que perdoa os nossos pecados e nos torna justos e santos em todo o nosso ser. Isto tem lugar por meio da graça do Espírito Santo, que nos foi merecida pela paixão de Cristo e nos foi dada no Baptismo. A justificação inicia a resposta livre do homem, ou seja, a fé em Cristo e a colaboração com a graça do Espírito Santo." },
                new() { Titulo = "423. O que é a graça que justifica?", Texto = "A graça é o dom gratuito que Deus nos dá para nos tornar participantes da sua vida trinitária e capaz de agir por amor d'Ele. É chamada graça habitual ou santificante ou deificante, pois nos santifica e diviniza. É sobrenatural, porque depende inteiramente da iniciativa gratuita de Deus e ultrapassa as capacidades da inteligência e das forças do homem. Escapa, portanto, à nossa experiência." },
                new() { Titulo = "424. Que outros tipos de graça existem?", Texto = "Para além da graça habitual, existem: as graças actuais (dons circunstanciais); as graças sacramentais (dons próprios de cada sacramento); as graças especiais ou carismas (que têm como fim o bem comum da Igreja), entre as quais as graças de estado, que acompanham o exercício dos ministérios eclesiais e das responsabilidades da vida." },
                new() { Titulo = "425. Qual é a relação entre a graça e a liberdade do homem?", Texto = "A graça precede, prepara e suscita a resposta livre do homem. Responde às aspirações profundas da liberdade humana, convida-a à colaboração e leva-a à sua perfeição." },
                new() { Titulo = "426. O que é o mérito?", Texto = "O mérito é o que dá direito à recompensa por uma acção boa. Em relação a Deus, o homem, de si, não pode merecer nada, tendo recebido gratuitamente tudo d'Ele. Todavia, Deus dá-lhe a possibilidade de adquirir méritos pela união à caridade de Cristo, fonte dos nossos méritos diante de Deus. Os méritos das obras boas devem por isso ser atribuídos antes de mais à graça de Deus e depois à vontade livre do homem." },
                new() { Titulo = "427. Que bens podemos merecer?", Texto = "Sob a moção do Espírito Santo, podemos merecer, para nós mesmos e para os outros, as graças úteis para nos santificarmos e para alcançar a vida eterna, bem como os bens temporais necessários segundo os desígnios de Deus. Ninguém pode merecer a graça primeira, que está na origem da conversão e da justificação." },
                new() { Titulo = "428. Somos todos chamados à santidade cristã?", Texto = "Todos os fiéis são chamados à santidade. Esta é a plenitude da vida cristã e a perfeição da caridade, que se obtém mediante a íntima união com Cristo e, n'Ele, com a Santíssima Trindade. O caminho de santificação do cristão, depois de ter passado pela cruz, terá o seu acabamento na ressurreição final dos justos, na qual Deus será tudo em todas as coisas." },
                new() { Titulo = "429. Como é que a Igreja alimenta a vida moral do cristão?", Texto = "A Igreja é a comunidade onde o cristão acolhe a Palavra de Deus que contém os ensinamentos da «Lei de Cristo» (Gal 6,2); recebe a graça dos sacramentos; une-se à oferta eucarística de Cristo de modo que a sua vida moral seja um culto espiritual; e aprende o exemplo da santidade da Virgem Maria e dos Santos." },
                new() { Titulo = "430. Porque é que o Magistério da Igreja intervém no campo moral?", Texto = "Porque é missão do Magistério da Igreja pregar a fé que deve ser acreditada e aplicada na vida prática. Essa missão estende-se também aos preceitos específicos da lei natural, porque a sua observância é necessária para a salvação." },
                new() { Titulo = "431. Qual a finalidade dos preceitos da Igreja?", Texto = "Os cinco preceitos da Igreja têm por fim garantir aos fiéis o mínimo indispensável do espírito de oração, da vida sacramental, do empenho moral e do crescimento do amor de Deus e do próximo." },
                new() { Titulo = "432. Quais são os preceitos da Igreja?", Texto = "São: 1) participar na missa do Domingo e Dias Santos de Guarda e abster-se de trabalhos e actividades que impeçam a santificação desses dias; 2) confessar os pecados recebendo o sacramento da Reconciliação ao menos uma vez cada ano; 3) comungar ao menos pela Páscoa da Ressurreição; 4) guardar a abstinência e jejuar nos dias marcados pela Igreja; 5) contribuir para as necessidades materiais da Igreja, cada um segundo as próprias possibilidades." },
                new() { Titulo = "433. Porque é que a vida moral dos cristãos é indispensável para o anúncio do Evangelho?", Texto = "Porque, com a sua vida conforme ao Senhor Jesus, os cristãos atraem os homens à fé no verdadeiro Deus, edificam a Igreja, modelam o mundo com o espírito do Evangelho e apressam a vinda do Reino de Deus." },
            }
        },

        // ─────────────────────────────────────────────────────────────────────
        // TERCEIRA PARTE — SECÇÃO 2: OS DEZ MANDAMENTOS
        // ─────────────────────────────────────────────────────────────────────

        new CatecismoPtTopico
        {
            Titulo = "Os Dez Mandamentos",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "434. «Mestre, que devo fazer de bom para alcançar a vida eterna?» (Mt 19,16)", Texto = "Ao jovem que lhe faz esta pergunta, Jesus responde: «Se queres entrar na vida, observa os mandamentos», e acrescenta: «Vem e segue-me» (Mt 19,16-21). Seguir Jesus implica observar os mandamentos. A Lei não é abolida, mas o homem é convidado a encontrá-la na pessoa do divino Mestre, que em si mesmo a cumpre perfeitamente, lhe revela o pleno significado e atesta a sua perenidade." },
                new() { Titulo = "435. Como é que Jesus interpreta a Lei?", Texto = "Jesus interpreta a Lei, à luz do duplo e único mandamento da caridade, que é a plenitude da Lei: «Amarás o Senhor teu Deus com todo o teu coração, com toda a tua alma e com toda a tua mente. Este é o maior e o primeiro dos mandamentos. E o segundo é semelhante ao primeiro: amarás o teu próximo como a ti mesmo. Destes dois mandamentos depende toda a Lei e os Profetas» (Mt 22,37-40)." },
                new() { Titulo = "436. O que significa o «Decálogo»?", Texto = "Decálogo significa «dez palavras» (Ex 34,28). Estas palavras resumem a Lei, dada por Deus ao povo de Israel, no contexto da Aliança, por meio de Moisés. Este, ao apresentar os mandamentos do amor a Deus (os três primeiros) e ao próximo (os outros sete), traça, para o povo eleito e para cada um em particular, o caminho duma vida liberta da escravidão do pecado." },
                new() { Titulo = "437. Qual a relação do Decálogo com a Aliança?", Texto = "O Decálogo compreende-se à luz da Aliança, na qual Deus se revela, dando a conhecer a sua vontade. Na observância dos mandamentos, o povo mostra a sua pertença a Deus e responde com gratidão à sua iniciativa de amor." },
                new() { Titulo = "438. Que importância dá a Igreja ao Decálogo?", Texto = "Fiel à Escritura e ao exemplo de Jesus, a Igreja reconhece ao Decálogo uma importância e um significado basilares. Os cristãos estão obrigados a observá-lo." },
                new() { Titulo = "439. Porque é que o Decálogo constitui uma unidade orgânica?", Texto = "O Decálogo constitui um conjunto orgânico e indissociável, porque cada mandamento remete para os outros e para o todo do Decálogo. Por isso, transgredir um mandamento é infringir toda a Lei." },
                new() { Titulo = "440. Porque é que o Decálogo obriga gravemente?", Texto = "Porque enuncia deveres fundamentais do homem para com Deus e para com o próximo." },
                new() { Titulo = "441. É possível observar o Decálogo?", Texto = "Sim, porque Cristo, sem o qual nada podemos fazer, nos torna capazes de observá-lo, com o dom do seu Espírito e da sua graça." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "O Primeiro Mandamento",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "442. Que implica a afirmação: «Eu sou o Senhor teu Deus» (Ex 20,2)?", Texto = "Implica, para o fiel, guardar e praticar as três virtudes teologais e evitar os pecados que se lhes opõem. A fé crê em Deus e rejeita o que lhe é contrário, como, por exemplo, a dúvida voluntária, a incredulidade, a heresia, a apostasia e o cisma. A esperança é a expectativa confiante da visão bem-aventurada de Deus e da sua ajuda, evitando o desespero e a presunção. A caridade ama a Deus sobre todas as coisas: são rejeitadas portanto a indiferença, a ingratidão, a tibieza, a acédia ou preguiça espiritual e o ódio a Deus, que nasce do orgulho." },
                new() { Titulo = "443. Que implica a Palavra do Senhor: «Adorarás o Senhor teu Deus e só a Ele prestarás culto» (Mt 4,10)?", Texto = "Implica adorar a Deus como Senhor de tudo o que existe; prestar-lhe o culto devido individual e comunitariamente; rezar-lhe com expressões de louvor, de acção de graças, de intercessão e de súplica; oferecer-Lhe sacrifícios, sobretudo o sacrifício espiritual da nossa vida, em união com o sacrifício perfeito de Cristo; e manter as promessas e os votos que Lhe fizermos." },
                new() { Titulo = "444. Como é que a pessoa realiza o próprio direito de prestar culto a Deus na verdade e na liberdade?", Texto = "Todo o homem tem o direito e o dever moral de procurar a verdade, em especial no que se refere a Deus e à sua Igreja, e, uma vez conhecida, de a abraçar e guardar fielmente, prestando a Deus um culto autêntico. Ao mesmo tempo, a dignidade da pessoa humana requer que, em matéria religiosa, ninguém seja forçado a agir contra a própria consciência nem seja impedido de agir em conformidade com ela, dentro dos limites da ordem pública, privada ou publicamente, de forma individual ou associada." },
                new() { Titulo = "445. Que proíbe Deus ao ordenar: «Não terás outros deuses perante Mim» (Ex 20,2)?", Texto = "Este mandamento proíbe: o politeísmo e a idolatria, que diviniza uma criatura, o poder, o dinheiro, e até mesmo o demónio; a superstição, que é um desvio do culto devido ao verdadeiro Deus, e que se expressa nas várias formas de adivinhação, magia, feitiçaria e espiritismo; a irreligião, expressa no tentar a Deus com palavras ou actos, no sacrilégio, que profana pessoas ou coisas sagradas sobretudo a Eucaristia, e na simonia, que pretende comprar ou vender realidades espirituais; o ateísmo, que nega a existência de Deus, fundando-se muitas vezes numa falsa concepção de autonomia humana; o agnosticismo, segundo o qual nada se poder saber de Deus, e que inclui o indiferentismo e o ateísmo prático." },
                new() { Titulo = "446. Ao dizer: «não farás para ti qualquer imagem esculpida» (Ex 20,3) proíbe-se o culto das imagens?", Texto = "No Antigo Testamento, este mandamento proíbe representar o Deus absolutamente transcendente. Porém, a partir da Encarnação do Filho de Deus, o culto cristão das imagens sagradas é justificado (como afirma o segundo Concílio de Niceia, de 787), porque se funda no Mistério do Filho de Deus feito homem, no qual Deus transcendente se torna visível. Não se trata duma adoração da imagem, mas de uma veneração de quem nela é representado: Cristo, a Virgem, os Anjos e os Santos." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "O Segundo Mandamento",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "447. Como respeitar a santidade do Nome de Deus?", Texto = "Invocando, bendizendo, louvando e glorificando o santo Nome de Deus. Deve pois ser evitado o abuso de invocar o Nome de Deus para justificar um crime, e ainda todo o uso inconveniente do seu Nome, como a blasfémia, que por sua natureza é um pecado grave, as imprecações e a infidelidade às promessas feitas em Nome de Deus." },
                new() { Titulo = "448. Porque se proíbe o juramento falso?", Texto = "Porque, assim, se chama a Deus, que é a própria Verdade, como testemunha da mentira. «Não jurar nem pelo Criador, nem pela criatura, senão com verdade, por necessidade e com reverência» (S. Inácio de Loiola)." },
                new() { Titulo = "449. O que é o perjúrio?", Texto = "É fazer, sob juramento, uma promessa com intenção de a não manter ou de violar a promessa feita sob juramento. É um pecado grave contra Deus, que é sempre fiel às suas promessas." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "O Terceiro Mandamento",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "450. Porque é que Deus «abençoou o dia de Sábado e o declarou sagrado» (Ex 20,11)?", Texto = "Porque o dia de Sábado recorda o repouso de Deus no sétimo dia da criação e também a libertação de Israel da escravidão do Egipto e a Aliança que Deus estabeleceu com o povo." },
                new() { Titulo = "451. Qual a atitude de Jesus em relação ao Sábado?", Texto = "Jesus reconhece a santidade do Sábado e, com a sua autoridade divina, dá-lhe a sua interpretação autêntica: «O Sábado foi feito para o homem e não o homem para o Sábado» (Mc 2,27)." },
                new() { Titulo = "452. Porque motivo, para os cristãos, o Sábado é substituído pelo Domingo?", Texto = "Porque o Domingo é o dia da ressurreição de Cristo. Como «primeiro dia da semana» (Mc 16,2) ele evoca a primeira criação; como «oitavo dia», que segue o Sábado, significa a nova criação, inaugurada com a Ressurreição de Cristo. Tornou-se assim para os cristãos o primeiro de todos os dias e de todas as festas: o dia do Senhor, no qual Ele, com a sua Páscoa, leva à realização a verdade espiritual do Sábado judaico e anuncia o repouso eterno do homem em Deus." },
                new() { Titulo = "453. Como santificar o Domingo?", Texto = "Os cristãos santificam o Domingo e as festas de preceito participando na Eucaristia do Senhor e abstendo-se também das actividades que o impedem de prestar culto a Deus e perturbam a alegria própria do dia do Senhor ou o devido descanso da mente e do corpo. São permitidas as actividades ligadas a necessidades familiares ou a serviços de grande utilidade social, desde que não criem hábitos prejudiciais à santificação do Domingo, à vida de família e à saúde." },
                new() { Titulo = "454. Porque é importante reconhecer civilmente o Domingo como dia festivo?", Texto = "Para que todos possam gozar de repouso suficiente e de tempo livre, que lhes permitam cuidar da vida religiosa, familiar, cultural e social; para dispor de tempo propício à meditação, reflexão, silêncio e estudo; e para fazer boas obras, servir os doentes e os anciãos." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "O Quarto Mandamento",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "455. O que nos manda o quarto mandamento?", Texto = "Manda honrar e respeitar os nossos pais e aqueles que Deus, para o nosso bem, revestiu com a sua autoridade." },
                new() { Titulo = "456. Qual é a natureza da família no plano de Deus?", Texto = "Um homem e uma mulher, unidos em matrimónio, formam com os filhos uma família. Deus instituiu a família e dotou-a da sua constituição fundamental. O matrimónio e a família são ordenados ao bem dos esposos e à procriação e educação dos filhos. Entre os membros da família estabelecem-se relações pessoais e responsabilidades primárias. Em Cristo, a família torna-se igreja doméstica, porque ela é comunidade de fé, de esperança e de amor." },
                new() { Titulo = "457. Que lugar ocupa a família na sociedade?", Texto = "A família é a célula originária da sociedade humana e precede qualquer reconhecimento da autoridade pública. Os princípios e os valores familiares constituem o fundamento da vida social. A vida de família é uma iniciação à vida da sociedade." },
                new() { Titulo = "458. Quais os deveres da sociedade em relação à família?", Texto = "A sociedade tem o dever de sustentar e consolidar o matrimónio e a família, no respeito também do princípio de subsidiariedade. Os poderes públicos devem respeitar, proteger e favorecer a verdadeira natureza do matrimónio e da família, a moral pública, os direitos dos pais e a prosperidade doméstica." },
                new() { Titulo = "459. Quais os deveres dos filhos para com os pais?", Texto = "Em relação aos pais, os filhos devem respeito (piedade filial), reconhecimento, docilidade e obediência, contribuindo assim, também com as boas relações entre irmãos e irmãs, para o crescimento da harmonia e da santidade de toda a vida familiar. Se os pais se encontrarem em situação de indigência, de doença, de solidão ou de velhice, os filhos adultos devem-lhes ajuda moral e material." },
                new() { Titulo = "460. Quais os deveres dos pais para com os filhos?", Texto = "Os pais, participantes da paternidade divina, são os primeiros responsáveis da educação dos filhos e os primeiros anunciadores da fé. Têm o dever de amar e respeitar os filhos como pessoas e filhos de Deus e, dentro do possível, de prover às suas necessidades materiais e espirituais, escolhendo para eles uma escola adequada e ajudando-os com prudentes conselhos na escolha da profissão e do estado de vida. Em particular, têm a missão de educá-los na fé cristã." },
                new() { Titulo = "461. Como é que os pais educam os filhos na fé cristã?", Texto = "Principalmente com o exemplo, a oração, a catequese familiar e a participação na vida eclesial." },
                new() { Titulo = "462. Os laços familiares são um bem absoluto?", Texto = "Os laços familiares são importantes mas não absolutos, porque a primeira vocação do cristão é seguir Jesus, amando-o: «Quem ama o pai ou a mãe mais do que a Mim, não é digno de Mim; quem ama a filha ou o filho mais do que a Mim não é digno de Mim» (Mt 10,37). Os pais devem, com alegria, ajudar os filhos no seguimento de Jesus, em todos os estados de vida, mesmo na vida consagrada ou no ministério sacerdotal." },
                new() { Titulo = "463. Como exercer a autoridade nos diferentes âmbitos da sociedade civil?", Texto = "A autoridade deve ser exercida, como um serviço, respeitando os direitos fundamentais da pessoa humana, uma justa hierarquia de valores, as leis, a justiça distributiva, e o princípio de subsidiariedade. No exercício da autoridade, cada um deve procurar o interesse da comunidade em vez do próprio e deve inspirar as suas decisões na verdade acerca de Deus, do homem e do mundo." },
                new() { Titulo = "464. Quais os deveres dos cidadãos em relação às autoridades civis?", Texto = "Os que estão submetidos à autoridade vejam os superiores como representantes de Deus e colaborem lealmente no bom funcionamento da vida pública e social. Isto comporta o amor e o serviço da pátria, o direito e o dever de votar, o pagamento dos impostos, a defesa do país e o direito a uma crítica construtiva." },
                new() { Titulo = "465. Quando é que o cidadão não deve obedecer à autoridade civil?", Texto = "Em consciência, o cidadão não deve obedecer quando os mandamentos das autoridades civis se opõem às exigências da ordem moral: «É necessário obedecer mais a Deus do que aos homens» (Act 5,29)." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "O Quinto Mandamento",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "466. Porque respeitar a vida humana?", Texto = "Porque é sagrada. Desde o seu início ela supõe a acção criadora de Deus e mantém-se para sempre numa relação especial com o Criador, seu único fim. A ninguém é lícito destruir directamente um ser humano inocente, pois é um acto gravemente contrário à dignidade da pessoa e à santidade do Criador. «Não causarás a morte do inocente e do justo» (Ex 23, 7)." },
                new() { Titulo = "467. Porque é que a legítima defesa das pessoas e das sociedades não vai contra tal norma?", Texto = "Porque com a legítima defesa se exerce a escolha de defender e valorizar o direito à própria vida e à dos outros, e não a escolha de matar. Para quem tem responsabilidade pela vida do outro, a legítima defesa pode até ser um dever grave. Todavia ela não deve comportar um uso da violência maior que o necessário." },
                new() { Titulo = "468. Para que serve uma pena?", Texto = "A pena, infligida por uma legítima autoridade pública, tem como objectivo compensar a desordem introduzida pela culpa, preservar a ordem pública e a segurança das pessoas, e contribuir para a emenda dos culpados." },
                new() { Titulo = "469. Que pena se pode aplicar?", Texto = "A pena infligida deve ser proporcionada à gravidade do delito. Hoje, na sequência das possibilidades do Estado para reprimir o crime tornando inofensivo o culpado, os casos de absoluta necessidade da pena de morte «são agora muito raros, se não mesmo praticamente inexistentes» (Evangelium vitae). Quando forem suficientes os meios incruentos, a autoridade deve limitar-se ao seu uso, porque correspondem melhor às condições concretas do bem comum, são mais conformes à dignidade da pessoa humana e não retiram definitivamente ao culpado a possibilidade de se redimir." },
                new() { Titulo = "470. Que proíbe o quinto mandamento?", Texto = "O quinto mandamento proíbe como gravemente contrários à lei moral: o homicídio directo e voluntário e a cooperação nele; o aborto directo, querido como fim ou como meio, e também a cooperação nele, crime que leva consigo a pena de excomunhão, porque o ser humano, desde a sua concepção, deve ser, em modo absoluto, respeitado e protegido totalmente; a eutanásia directa, que consiste em pôr fim à vida de pessoas com deficiências, doentes ou moribundas, mediante um acto ou omissão duma acção devida; o suicídio e a cooperação voluntária nele, enquanto ofensa grave ao justo amor de Deus, de si e do próximo: a responsabilidade pode ser ainda agravada por causa do escândalo ou atenuada por especiais perturbações psíquicas ou temores graves." },
                new() { Titulo = "471. O que é consentido, medicamente, quando a morte é tida como iminente?", Texto = "Os cuidados habitualmente devidos a uma pessoa doente não podem ser legitimamente interrompidos. São legítimos o uso de analgésicos, que não têm como fim a morte, e também a renúncia ao «excesso terapêutico», isto é, à utilização de tratamentos médicos desproporcionados e sem esperança razoável de êxito positivo." },
                new() { Titulo = "472. Porque é que a sociedade deve proteger o embrião?", Texto = "O direito inalienável à vida de cada ser humano, desde a sua concepção, é um elemento constitutivo da sociedade civil e da sua legislação. Quando o Estado não coloca a sua força ao serviço dos direitos de todos e em particular dos mais fracos, e entre eles dos concebidos ainda não nascidos, passam a ser minados os próprios fundamentos do Estado de direito." },
                new() { Titulo = "473. Como se evita o escândalo?", Texto = "O escândalo, que consiste em levar alguém a fazer o mal, evita-se respeitando a alma e o corpo da pessoa. Se alguém induz deliberadamente outro a pecar gravemente, comete uma culpa grave." },
                new() { Titulo = "474. Que deveres temos em relação ao corpo?", Texto = "O dever dum razoável cuidado da saúde física, da nossa e da dos outros, evitando todavia o culto do corpo e toda a espécie de excessos. Evitar o uso de estupefacientes, com gravíssimos danos para a saúde e a vida humana e também o abuso dos alimentos, do álcool, do tabaco e dos remédios." },
                new() { Titulo = "475. Quando são moralmente legítimas as experiências científicas, médicas ou psicológicas, sobre pessoas ou grupos humanos?", Texto = "São moralmente legítimas se estão ao serviço do bem integral da pessoa e da sociedade e não trazem riscos desproporcionados à vida e à integridade física e psíquica dos indivíduos, que devem ser oportunamente esclarecidos e dar o seu consentimento." },
                new() { Titulo = "476. São consentidos a transplantação e doação de órgãos, antes e depois da morte?", Texto = "A transplantação de órgãos é moralmente aceitável com o consentimento do doador e sem riscos excessivos para ele. Para o acto nobre da doação de órgãos depois da morte, deve acertar-se plenamente a morte real do doador." },
                new() { Titulo = "477. Quais as práticas contra o respeito à integridade corpórea da pessoa humana?", Texto = "São: os raptos e sequestros de pessoas, o terrorismo, a tortura, as violências, a esterilização directa. As amputações e as mutilações duma pessoa só são moralmente consentidas para indispensáveis fins terapêuticos da mesma." },
                new() { Titulo = "478. Que cuidado ter com os moribundos?", Texto = "Os moribundos têm direito a viver com dignidade os últimos momentos da sua vida terrena, sobretudo com a ajuda da oração e dos sacramentos que preparam para o encontro com o Deus vivo." },
                new() { Titulo = "479. Como tratar os corpos dos defuntos?", Texto = "Os corpos dos defuntos devem ser tratados com respeito e caridade. A sua cremação é permitida, se não puser em causa a fé na ressurreição dos corpos." },
                new() { Titulo = "480. Que pede o Senhor a cada um em ordem à paz?", Texto = "O Senhor, que proclama «bem-aventurados os obreiros da paz» (Mt 5, 9), pede a paz do coração e denuncia a imoralidade da ira, que é desejo de vingança pelo mal recebido, e do ódio, que leva a desejar o mal ao próximo. Estas atitudes, se voluntárias e consentidas em matéria de grande importância, são pecados graves contra a caridade." },
                new() { Titulo = "481. O que é a paz no mundo?", Texto = "A paz no mundo, a qual é exigida para o respeito e desenvolvimento da vida humana, não é a simples ausência de guerra ou equilíbrio entre as forças em contraste, mas é «a tranquilidade da ordem» (S. Agostinho), «fruto da justiça» (Is 32, 17) e efeito da caridade. A paz terrena é imagem e fruto da paz de Cristo." },
                new() { Titulo = "482. O que exige a paz no mundo?", Texto = "Exige a distribuição equitativa e a tutela dos bens das pessoas, a livre comunicação entre os seres humanos, o respeito da dignidade das pessoas e dos povos, a assídua prática da justiça e da fraternidade." },
                new() { Titulo = "483. Quando é moralmente consentido o uso da força militar?", Texto = "O uso da força militar é moralmente justificado pela presença contemporânea das seguintes condições: certeza de um dano permanente e grave; ineficácia doutras alternativas pacíficas; fundadas possibilidades de êxito; ausência de males piores, considerado o poder actual dos meios de destruição." },
                new() { Titulo = "484. A quem compete a avaliação rigorosa dessas condições, em caso de guerra?", Texto = "Compete ao juízo prudente dos governantes, aos quais compete também o direito de impor aos cidadãos a obrigação da defesa nacional, salvo o direito pessoal à objecção de consciência, a realizar-se com outra forma de serviço à comunidade humana." },
                new() { Titulo = "485. O que exige a lei moral, em caso de guerra?", Texto = "A lei moral permanece sempre válida, mesmo em caso de guerra. Devem tratar-se com humanidade os não combatentes, os soldados feridos e os prisioneiros. As acções deliberadamente contrárias ao direito dos povos e as disposições que as impõem são crimes que a obediência cega não pode desculpar. Devem-se condenar as destruições em massa, bem como o extermínio de um povo ou duma minoria étnica, que são pecados gravíssimos e obrigam moralmente a resistir às ordens de quem os ordena." },
                new() { Titulo = "486. O que se deve fazer para evitar a guerra?", Texto = "Devemos fazer tudo o que é razoavelmente possível para evitar de qualquer modo a guerra, devido aos males e injustiças que ela provoca. É necessário, em especial, evitar a acumulação e comércio de armas não devidamente regulamentadas pelos poderes legítimos; as injustiças sobretudo económicas e sociais; as discriminações étnicas e religiosas; a inveja, a desconfiança, o orgulho e o espírito de vingança. Tudo quanto se fizer para eliminar estas e outras desordens ajudará a construir a paz e a evitar a guerra." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "O Sexto Mandamento",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "487. Qual a missão da pessoa humana em relação à própria identidade sexual?", Texto = "Deus criou o ser humano como homem e mulher, com igual dignidade pessoal, e inscreveu nele a vocação ao amor e à comunhão. Compete a cada um aceitar a sua identidade sexual, reconhecendo a sua importância para a pessoa toda, bem como o valor da especificidade e da complementaridade." },
                new() { Titulo = "488. O que é a castidade?", Texto = "A castidade é a integração positiva da sexualidade na pessoa. A sexualidade torna-se verdadeiramente humana quando é bem integrada na relação pessoa a pessoa. A castidade é uma virtude moral, um dom de Deus, uma graça, um fruto do Espírito." },
                new() { Titulo = "489. O que supõe a virtude da castidade?", Texto = "Supõe a aprendizagem do domínio de si, que é uma pedagogia de liberdade humana aberta ao dom de si. Para tal fim, é necessária uma educação integral e permanente, através de etapas graduais de crescimento." },
                new() { Titulo = "490. Quais os meios que ajudam a viver a castidade?", Texto = "São numerosos os meios à disposição: a graça de Deus, a ajuda dos sacramentos, a oração, o conhecimento de si, a prática duma ascese adaptada às situações, o exercício das virtudes morais, em particular da virtude da temperança, que procura fazer com que as paixões sejam guiadas pela razão." },
                new() { Titulo = "491. Como é que todos são chamados a viver a castidade?", Texto = "Todos, seguindo Cristo modelo de castidade, são chamados a levar uma vida casta, segundo o próprio estado de vida: uns na virgindade ou no celibato consagrado, forma eminente de uma mais fácil entrega a Deus com um coração indiviso; os outros, se casados, vivendo a castidade conjugal; os não casados vivem a castidade na continência." },
                new() { Titulo = "492. Quais os principais pecados contra a castidade?", Texto = "São pecados gravemente contrários à castidade, cada um segundo a natureza do objecto: o adultério, a masturbação, a fornicação, a pornografia, a prostituição, o estupro, os actos homossexuais. Estes pecados são expressão do vício da luxúria. Cometidos contra os menores, são atentados ainda mais graves contra a sua integridade física e moral." },
                new() { Titulo = "493. Porque é que o sexto mandamento, que diz «não cometerás adultério», proíbe todos os pecados contra a castidade?", Texto = "Embora no texto bíblico se leia «não cometerás adultério» (Ex 20,14), a Tradição da Igreja segue complexivamente todos os ensinamentos morais do Antigo e Novo Testamento, e considera o sexto mandamento como englobando todos os pecados contra a castidade." },
                new() { Titulo = "494. Qual a missão das autoridades civis em relação à castidade?", Texto = "As autoridades civis, obrigadas a promover o respeito pela dignidade da pessoa, devem contribuir para criar um ambiente favorável à castidade, mesmo impedindo, com leis apropriadas, a difusão de algumas das chamadas graves ofensas à castidade, para proteger sobretudo os menores e os mais débeis." },
                new() { Titulo = "495. Quais os bens do amor conjugal a que a sexualidade se ordena?", Texto = "Os bens do amor conjugal, que para os baptizados é santificado pelo sacramento do matrimónio, são: a unidade, a fidelidade, a indissolubilidade e a abertura à fecundidade." },
                new() { Titulo = "496. Qual o significado do acto conjugal?", Texto = "O acto conjugal tem um duplo significado: unitivo (a mútua doação dos esposos) e procriador (a abertura à transmissão da vida). Ninguém deve quebrar a conexão inquebrável que Deus quis entre os dois significados do acto conjugal, excluindo um deles." },
                new() { Titulo = "497. Quando é que a regulação dos nascimentos é moral?", Texto = "A regulação dos nascimentos, que é uma componente da paternidade e maternidade responsáveis, é objectivamente conforme à moralidade quando é realizada pelos esposos sem imposições externas, nem por egoísmo, mas com base em motivos sérios e o recurso a métodos conformes aos critérios objectivos da moralidade, isto é, com a continência periódica e o recurso aos períodos infecundos." },
                new() { Titulo = "498. Quais os meios imorais na regulação dos nascimentos?", Texto = "É intrinsecamente imoral toda a acção – como, por exemplo, a esterilização directa ou a contracepção – que, na previsão do acto conjugal ou na sua realização ou no desenvolvimento das suas consequências naturais, se proponha, como objectivo ou como meio, impedir a procriação." },
                new() { Titulo = "499. Porque é que a inseminação e a fecundação artificiais são imorais?", Texto = "São imorais porque dissociam a procriação do acto com que os esposos se entregam mutuamente, instaurando assim um domínio da técnica sobre a origem e o destino da pessoa humana. Além disso, a inseminação e a fecundação heteróloga, com o recurso a técnicas que envolvem uma pessoa estranha ao casal dos esposos, prejudicam o direito do filho a nascer dum pai e duma mãe conhecidos por ele, ligados entre si pelo matrimónio e tendo o direito exclusivo a tornarem-se pais, só um através do outro." },
                new() { Titulo = "500. Como deve ser considerado um filho?", Texto = "O filho é um dom de Deus, o maior dom do matrimónio. Não existe um direito a ter filhos («o filho exigido, a todo o custo»). Existe, ao contrário, o direito do filho a ser o fruto do acto conjugal dos seus progenitores e o direito a ser respeitado como pessoa desde o momento da sua concepção." },
                new() { Titulo = "501. Que devem fazer os esposos sem filhos?", Texto = "No caso em que o dom do filho não lhes tivesse sido concedido, os esposos, esgotados os recursos médicos legítimos, podem mostrar a sua generosidade, mediante o cuidado ou a adopção, ou então realizando serviços significativos em favor do próximo. Deste modo, realizarão uma preciosa fecundidade espiritual." },
                new() { Titulo = "502. Quais são as ofensas contra a dignidade do matrimónio?", Texto = "São: o adultério, o divórcio, a poligamia, o incesto, a união de facto (convivência, concubinato) e o acto sexual antes ou fora do matrimónio." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "O Sétimo Mandamento",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "503. Que diz o sétimo mandamento?", Texto = "Ele enuncia o destino, a distribuição universal e a propriedade privada dos bens, e ainda o respeito das pessoas, dos seus bens e da integridade da criação. A Igreja encontra fundada neste mandamento também a sua doutrina social, que compreende o recto agir na actividade económica e na vida social e política, o direito e o dever do trabalho humano, a justiça e a solidariedade entre as nações, o amor aos pobres." },
                new() { Titulo = "504. Em que condições existe o direito à propriedade privada?", Texto = "O direito à propriedade privada existe se ela for adquirida ou recebida de modo justo e desde que seja respeitado o destino universal dos bens para a satisfação das necessidades fundamentais de todos os homens." },
                new() { Titulo = "505. Qual é o fim da propriedade privada?", Texto = "O fim da propriedade privada é a garantia da liberdade e da dignidade de cada uma das pessoas, ajudando-as a satisfazer as necessidades fundamentais próprias daqueles por quem se tem a responsabilidade e dos outros que vivem em necessidade." },
                new() { Titulo = "506. O que prescreve o sétimo mandamento?", Texto = "O sétimo mandamento prescreve o respeito dos bens alheios, mediante a prática da justiça e da caridade, da temperança e da solidariedade. Em particular, exige o respeito das promessas e dos contractos estipulados; a reparação da injustiça cometida e a restituição do mal feito; o respeito pela integridade da criação mediante o uso prudente e moderado dos recursos minerais, vegetais e animais que há no universo, com especial atenção para com as espécies ameaçadas de extinção." },
                new() { Titulo = "507. Como é que o homem se deve comportar com os animais?", Texto = "O homem deve tratar os animais, criaturas de Deus, com benevolência, evitando quer o amor excessivo para com eles, quer o seu uso indiscriminado, sobretudo para experimentações científicas efectuadas para lá dos limites razoáveis e com sofrimentos inúteis para os próprios animais." },
                new() { Titulo = "508. Que proíbe o sétimo mandamento?", Texto = "O sétimo mandamento, antes de mais, proíbe o furto que é a usurpação do bem alheio contra a razoável vontade do seu proprietário. É o que também sucede no pagamento de salários injustos; na especulação sobre o valor dos bens para obter vantagens com prejuízo para os outros; na falsificação de cheques ou facturas. Proíbe, além disso, cometer fraudes fiscais ou comerciais, causar um dano às propriedades privadas ou públicas. Proíbe também a usura, a corrupção, o abuso privado dos bens sociais, os trabalhos culpavelmente mal feitos e o esbanjamento." },
                new() { Titulo = "509. Qual é o conteúdo da doutrina social da Igreja?", Texto = "A doutrina social da Igreja, como desenvolvimento orgânico da verdade do Evangelho sobre a dignidade da pessoa humana e sobre a sua dimensão social, contém princípios de reflexão, formula critérios de juízo, oferece normas e orientações para a acção." },
                new() { Titulo = "510. Quando é que a Igreja intervém em matéria social?", Texto = "A Igreja emite um juízo moral em matéria económica e social quando isto é exigido pelos direitos fundamentais da pessoa, do bem comum ou da salvação das almas." },
                new() { Titulo = "511. Como se deve exercer a vida social e económica?", Texto = "Segundo os seus próprios métodos, no âmbito da ordem moral, ao serviço da pessoa humana na sua integridade e de toda a comunidade humana, no respeito da justiça social. Ela deve ter o homem como seu autor, centro e fim." },
                new() { Titulo = "512. O que é que se opõe à doutrina social da Igreja?", Texto = "Opõem-se à doutrina social da Igreja os sistemas económicos e sociais que sacrificam os direitos fundamentais das pessoas ou que fazem do lucro a sua regra exclusiva ou o seu fim último. Por isso, a Igreja rejeita as ideologias associadas, nos tempos modernos, ao «comunismo» ou às formas ateias e totalitárias de «socialismo». Rejeita, além disso, na prática do «capitalismo», o individualismo e o primado absoluto da lei do mercado sobre o trabalho humano." },
                new() { Titulo = "513. Qual é o significado do trabalho para o homem?", Texto = "O trabalho é para o homem um dever e um direito, mediante o qual ele colabora com Deus criador. Com efeito, trabalhando com empenho e competência, a pessoa põe em acção capacidades inscritas na sua natureza, exalta os dons do Criador e os talentos recebidos, sustenta-se a si e aos seus familiares, serve a comunidade humana. Além disso, com a graça de Deus, o trabalho pode ser meio de santificação e de colaboração com Cristo para a salvação dos outros." },
                new() { Titulo = "514. A que tipo de trabalho tem direito a pessoa humana?", Texto = "A todos deve ser possível obter um trabalho seguro e honesto, sem discriminações injustas, respeitando a livre iniciativa económica e uma justa retribuição." },
                new() { Titulo = "515. Qual a responsabilidade do Estado acerca do trabalho?", Texto = "Compete ao Estado fornecer a segurança das garantias das liberdades individuais e da propriedade, para além duma moeda estável e de serviços públicos eficientes; compete-lhe ainda zelar e orientar o exercício dos direitos humanos no sector económico. A sociedade deve ajudar os cidadãos a encontrar trabalho, conforme as circunstâncias." },
                new() { Titulo = "516. Qual a missão dos responsáveis das empresas?", Texto = "Os responsáveis das empresas têm a responsabilidade económica e ecológica das suas operações. Estão obrigados a ter em conta o bem das pessoas e não apenas o aumento dos lucros, embora estes sejam necessários para assegurar os investimentos, o futuro das empresas, o emprego e o bom andamento da vida económica." },
                new() { Titulo = "517. Quais os deveres dos trabalhadores?", Texto = "Devem realizar o seu trabalho, com consciência, competência e dedicação, procurando resolver, com o diálogo, eventuais controvérsias. O recurso à greve não violenta é moralmente legítimo quando se apresenta como instrumento necessário, em vista dum benefício proporcionado e tendo em conta o bem comum." },
                new() { Titulo = "518. Como realizar a justiça e a solidariedade entre as nações?", Texto = "No plano internacional, todas as nações e instituições devem actuar na solidariedade e na subsidiariedade, com vista a eliminar, ou pelo menos reduzir, a miséria, a desigualdade dos recursos e dos meios económicos, as injustiças económicas e sociais, a exploração das pessoas, a acumulação da dívida dos países pobres, os mecanismos perversos que criam obstáculos ao progresso dos países menos desenvolvidos." },
                new() { Titulo = "519. Como é que os cristãos participam na vida política e social?", Texto = "Os fiéis leigos intervêm directamente na vida política e social animando, com espírito cristão, as realidades temporais e colaborando com todos, como autênticas testemunhas do Evangelho e promotores da paz e da justiça." },
                new() { Titulo = "520. Em que se inspira o amor aos pobres?", Texto = "O amor aos pobres inspira-se no Evangelho das bem-aventuranças e no exemplo de Jesus com a sua constante atenção aos pobres. Jesus disse: «Todas as vezes que fizerdes isto a um só destes irmãos mais pequeninos, a Mim o fizestes» (Mt 25,40). O amor aos pobres manifesta-se na acção contra a pobreza material e contra as numerosas formas de pobreza cultural, moral e religiosa. As obras de misericórdia, espirituais e corporais e as numerosas instituições de beneficência que surgiram ao longo dos séculos, constituem um concreto testemunho do amor preferencial pelos pobres que caracteriza os discípulos de Jesus." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "O Oitavo Mandamento",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "521. Qual o dever do homem em relação à verdade?", Texto = "Toda a pessoa é chamada à sinceridade e à veracidade no agir e no falar. Cada um tem o dever de procurar a verdade e de aderir a ela, organizando toda a sua vida segundo as exigências da verdade. Em Jesus Cristo, a verdade de Deus manifestou-se na sua totalidade: Ele é a Verdade. Seguir Jesus é viver do «Espírito de verdade» (Jo 14,17) e evitar a duplicidade, a simulação e a hipocrisia." },
                new() { Titulo = "522. Como dar testemunho da verdade?", Texto = "O cristão deve testemunhar a verdade evangélica em todos os campos da actividade pública e privada, mesmo com o sacrifício da própria vida, se necessário. O martírio é o supremo testemunho dado em favor da verdade da fé." },
                new() { Titulo = "523. O que proíbe o oitavo mandamento?", Texto = "O oitavo mandamento proíbe: o falso testemunho, o perjúrio e a mentira, cuja gravidade se mede pela natureza da verdade que ela deforma, das circunstâncias, das intenções do mentiroso e dos danos causados às vítimas; o juízo temerário, a maledicência, a difamação, a calúnia, que lesam ou destroem a boa reputação e a honra a que a pessoa tem direito; a lisonja, a adulação ou complacência, sobretudo se finalizadas à realização de pecados graves ou à obtenção de vantagens ilícitas; uma culpa contra a verdade exige a reparação, quando se ocasionou dano a outrem." },
                new() { Titulo = "524. Que requer o oitavo mandamento?", Texto = "O oitavo mandamento requer o respeito da verdade, acompanhado pela discrição da caridade: na comunicação e na informação, que devem assegurar o bem pessoal e comum, a defesa da vida particular e o perigo de escândalo; na reserva dos segredos profissionais, que se devem sempre manter, salvo em casos excepcionais, por motivos graves e proporcionados. Exige-se também o respeito pelas confidências feitas sob o sigilo do segredo." },
                new() { Titulo = "525. Como usar os meios de comunicação social?", Texto = "A informação mediática deve estar ao serviço do bem comum, ser sempre verdadeira no conteúdo e, salva a justiça e a caridade, deve ser também íntegra. Além disso deve expressar-se em modo honesto e conveniente, respeitando escrupulosamente as leis morais, os direitos legítimos e a dignidade da pessoa." },
                new() { Titulo = "526. Qual a relação entre a verdade, a beleza e a arte sacra?", Texto = "A verdade é bela por si mesma. Ela comporta o esplendor da beleza espiritual. Além da palavra, existem numerosas formas de expressão da verdade, em especial as obras artísticas. São o fruto do talento dado por Deus e do esforço do homem. A arte sacra, para ser verdadeira e bela, deve evocar e glorificar o Mistério de Deus revelado em Cristo e conduzir à adoração e ao amor de Deus Criador e Salvador, Beleza excelsa de Verdade e de Amor." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "O Nono Mandamento",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "527. O que exige o nono mandamento?", Texto = "O nono mandamento exige vencer a concupiscência carnal nos pensamentos e nos desejos. A luta contra a concupiscência passa pela purificação do coração e pela prática da virtude da temperança." },
                new() { Titulo = "528. Que proíbe o nono mandamento?", Texto = "O nono mandamento proíbe cultivar pensamentos e desejos relativos às acções proibidas pelo sexto mandamento." },
                new() { Titulo = "529. Como chegar à pureza do coração?", Texto = "O baptizado, com a graça de Deus, em luta contra os desejos desordenados, chega à pureza do coração mediante a virtude e o dom da castidade, a pureza de intenção e do olhar exterior e interior, com a disciplina dos sentidos e da imaginação e pela oração." },
                new() { Titulo = "530. Quais as outras exigências da pureza?", Texto = "A pureza exige o pudor, que, preservando a intimidade da pessoa, exprime a delicadeza da castidade e orienta os olhares e os gestos em conformidade com a dignidade das pessoas e da sua comunhão. Ela liberta do erotismo difuso e afasta de tudo aquilo que favorece a curiosidade mórbida. Requer uma purificação do ambiente social, mediante uma luta constante contra a permissividade dos costumes, que assenta numa concepção errónea da liberdade humana." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "O Décimo Mandamento",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "531. Que exige e que proíbe o décimo mandamento?", Texto = "Este mandamento completa o precedente e exige uma atitude interior de respeito em relação à propriedade alheia. Proíbe a avidez, a cupidez desregrada dos bens dos outros e a inveja, que consiste na tristeza que se experimenta perante os bens alheios e o desejo imoderado de deles se apoderar." },
                new() { Titulo = "532. Que pede Jesus com a pobreza de coração?", Texto = "Jesus requer aos seus discípulos que O prefiram a tudo e a todos. O desprendimento das riquezas – segundo o espírito da pobreza evangélica – e o abandono à providência de Deus, que nos liberta da preocupação pelo amanhã, preparam-nos para a bem-aventurança dos «pobres em espírito, porque deles é já o reino dos céus» (Mt 5, 3)." },
                new() { Titulo = "533. Qual é o maior desejo do homem?", Texto = "O maior desejo do homem é ver a Deus. Este é o grito de todo o seu ser: «Quero ver a Deus!». De facto, o homem realiza a verdadeira e perfeita felicidade na visão e na bem-aventurança d'Aquele que o criou por amor e o atrai a Si no seu infinito amor." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "A Oração Cristã",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "534. O que é a oração?", Texto = "A oração consiste em elevar a alma a Deus ou em pedir a Deus bens conformes à sua vontade. Ela é sempre um dom de Deus que vem ao encontro do homem. A oração cristã é relação pessoal e viva dos filhos de Deus com o Pai infinitamente bom, com o seu Filho Jesus Cristo e com o Espírito Santo que habita no coração daqueles." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "A Revelação da Oração",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "535. Porque é que existe um chamamento universal à oração?", Texto = "Porque primeiramente Deus, através da criação, chama do nada todos os seres e ainda porque, mesmo depois da queda, o homem continua a ser capaz de reconhecer o seu Criador, conservando o desejo d'Aquele que o chamou à existência. Todas as religiões e, em especial, toda a história da salvação, testemunham este desejo de Deus por parte do homem, se bem que é sempre Deus que primeiro e incessantemente atrai cada uma das pessoas para o encontro misterioso da oração." },
                new() { Titulo = "536. Como é que Abraão é um modelo de oração?", Texto = "Abraão é um modelo de oração porque caminha na presença de Deus, O escuta e Lhe obedece. A sua oração é um combate da fé, porque ele continua a crer na fidelidade de Deus mesmo nos momentos de provação. Além disso, depois de receber na sua tenda a visita do Senhor, que lhe confia os seus desígnios, Abraão ousa interceder pelos pecadores, com audaciosa confiança." },
                new() { Titulo = "537. Como rezava Moisés?", Texto = "A oração de Moisés é o tipo da oração contemplativa: Deus, que, da Sarça ardente, chama Moisés, conversa muitas vezes e longamente com ele «face a face, como um homem com o seu amigo» (Ex 33,11). Nesta intimidade com Deus, Moisés recebe a força para interceder tenazmente em favor do povo: a sua oração prefigura assim a intercessão do único mediador, Cristo Jesus." },
                new() { Titulo = "538. Quais as relações do templo e do rei com a oração, no Antigo Testamento?", Texto = "À sombra da morada de Deus – a Arca da Aliança e mais tarde o templo – cresce a oração do Povo de Deus, sob a orientação dos seus pastores. Entre eles, David é o rei «segundo o coração de Deus», o pastor que reza pelo seu povo. A sua oração é um modelo da oração do povo pois é adesão à promessa divina e confiança cheia de amor n'Aquele que é o único Rei e Senhor." },
                new() { Titulo = "539. Qual a importância da oração na missão dos profetas?", Texto = "Os profetas recebem da oração luz e força para exortar o povo à fé e à conversão do coração. Entram numa grande intimidade com Deus e intercedem pelos irmãos, aos quais anunciam tudo o que viram e ouviram da parte do Senhor. Elias é o pai dos profetas, isto é, dos que procuram o Rosto de Deus. No Monte Carmelo, obtém o regresso do povo à fé, graças à intervenção de Deus, a quem suplica: «Responde-me Senhor, responde-me!» (1 Re 18,37)." },
                new() { Titulo = "540. Qual é a importância da oração dos salmos?", Texto = "Os Salmos são o vértice da oração no Antigo Testamento: a Palavra de Deus torna-se oração do homem. Inseparavelmente pessoal e comunitária, esta oração, inspirada pelo Espírito Santo, canta as maravilhas de Deus na criação e na história da salvação. Cristo rezou os Salmos, e deu-lhes pleno cumprimento. E é por isso que eles permanecem um elemento essencial e permanente da oração da Igreja, adaptados aos homens de todas as condições e de todos os tempos." },
                new() { Titulo = "541. Quem ensinou Jesus a rezar?", Texto = "Jesus, segundo o seu coração de homem, foi ensinado a rezar por sua Mãe e pela tradição judaica. Mas a sua oração brota duma fonte secreta, porque Ele é o Filho eterno de Deus, que, na sua santa humanidade, dirige a seu Pai a oração filial perfeita." },
                new() { Titulo = "542. Quando Jesus rezava?", Texto = "O Evangelho apresenta muitas vezes Jesus em oração. Ele retira-se para a solidão, mesmo de noite. Jesus reza antes dos momentos decisivos da sua missão ou da missão dos Apóstolos. De facto, toda a sua vida é oração, porque Ele existe numa comunhão constante de amor com o Pai." },
                new() { Titulo = "543. Como rezou Jesus na sua paixão?", Texto = "A oração de Jesus durante a agonia no Jardim de Getsemani e nas últimas palavras sobre a cruz revelam a profundidade da sua oração filial: Jesus conduz à sua realização o desígnio de amor do Pai e toma sobre si todas as angústias da humanidade, todas as interrogações e intercessões da história da salvação. Ele apresenta-as ao Pai que as acolhe e escuta, para lá de toda a esperança, ressuscitando-O dos mortos." },
                new() { Titulo = "544. Como Jesus nos ensina a rezar?", Texto = "Jesus ensina-nos a rezar, não só com a oração do Pai nosso, mas também com a sua própria oração. Assim, para além do conteúdo, ensina-nos as disposições requeridas para uma verdadeira oração: a pureza do coração que procura o Reino e perdoa aos inimigos; a confiança audaz e filial que se estende para além do que sentimos e compreendemos; a vigilância que protege o discípulo da tentação; a oração no Nome de Jesus, nosso Mediador junto do Pai." },
                new() { Titulo = "545. Porque é eficaz a nossa oração?", Texto = "A nossa oração é eficaz porque está unida à de Jesus mediante a fé. N'Ele, a oração cristã torna-se comunhão de amor com o Pai. Podemos, neste caso, apresentar os nossos pedidos a Deus e ser atendidos: «Pedi e recebereis, assim a vossa alegria será completa» (Jo 16,24)." },
                new() { Titulo = "546. Como é que a Virgem Maria rezava?", Texto = "A oração de Maria caracteriza-se pela fé e pela oferta generosa de todo o seu ser a Deus. A Mãe de Jesus é a Nova Eva, a «Mãe dos viventes»: ela pede a Jesus, seu Filho, pelas necessidades de todos os homens." },
                new() { Titulo = "547. Existe no Evangelho uma oração de Maria?", Texto = "Para além da intercessão de Maria em Caná da Galileia, o Evangelho apresenta-nos o Magnificat (Lc 1,46-55), cântico da Mãe de Deus e da Igreja, jubilosa acção de graças que se eleva do coração dos pobres porque a sua esperança foi realizada pelo cumprimento das promessas divinas." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "A Oração no Tempo da Igreja",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "548. Como rezava a primeira comunidade cristã de Jerusalém?", Texto = "No início dos Actos dos Apóstolos está escrito que na primeira comunidade de Jerusalém, educada pelo Espírito Santo na vida de oração, os crentes «eram assíduos ao ensino dos Apóstolos, fiéis à união fraterna, à fracção do pão e às orações» (Act 2, 42)." },
                new() { Titulo = "549. Como intervém o Espírito Santo na oração da Igreja?", Texto = "O Espírito Santo, Mestre interior da oração cristã, forma a Igreja para a vida de oração e a faz entrar cada vez mais profundamente na contemplação e na união com o insondável mistério de Cristo. As formas de oração, tais como as revelam os Escritos apostólicos e canónicos, permanecerão sempre normativas para a oração cristã." },
                new() { Titulo = "550. Quais são as formas essenciais da oração cristã?", Texto = "São a bênção e a adoração, a oração de petição e a intercessão, a acção de graças e o louvor. A Eucaristia contém e exprime todas as formas de oração." },
                new() { Titulo = "551. O que é a bênção?", Texto = "A bênção é a resposta do homem aos dons de Deus: nós bendizemos o Omnipotente que primeiramente nos abençoa e enche dos seus dons." },
                new() { Titulo = "552. Como se pode definir a adoração?", Texto = "A adoração é a prostração do homem que se reconhece criatura diante do seu Criador três vezes santo." },
                new() { Titulo = "553. Quais são as diversas formas da oração de petição?", Texto = "Pode ser um pedido de perdão ou mesmo uma súplica humilde e confiante em relação a todas as nossas necessidades espirituais ou materiais. Mas a primeira realidade a desejar é a vinda do Reino." },
                new() { Titulo = "554. Em que consiste a intercessão?", Texto = "A intercessão consiste no pedir em favor doutro. Ela conforma-nos e une-nos à oração de Jesus que intercede junto do Pai por todos os homens, em especial pelos pecadores. A intercessão deve estender-se também aos inimigos." },
                new() { Titulo = "555. Quando se dá a Deus acção de graças?", Texto = "A Igreja dá graças a Deus incessantemente, sobretudo ao celebrar a Eucaristia, na qual Cristo a faz participar na sua acção de graças ao Pai. Todos os acontecimentos se convertem para o cristão em motivo de acção de graças." },
                new() { Titulo = "556. O que é a oração de louvor?", Texto = "O louvor é a forma de oração que mais imediatamente reconhece que Deus é Deus. É completamente desinteressada: canta Deus por Ele ser quem é e glorifica-O porque Ele é." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "A Tradição da Oração",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "557. Qual a importância da Tradição em relação à oração?", Texto = "Na Igreja, é através duma Tradição viva que o Espírito Santo ensina os filhos de Deus a orar. A oração não se reduz, com efeito, ao brotar espontâneo dum impulso interior, mas implica contemplação, estudo e compreensão das realidades espirituais que se experimentam." },
                new() { Titulo = "558. Quais as fontes da oração cristã?", Texto = "São: a Palavra de Deus, que nos dá a «sublime ciência de Cristo» (Filp 3,8); a Liturgia da Igreja que anuncia, actualiza e comunica o mistério da salvação; as virtudes teologais; as situações quotidianas, porque nelas podemos encontrar Deus." },
                new() { Titulo = "559. Na Igreja existem diferentes caminhos de oração?", Texto = "Na Igreja existem diferentes caminhos de oração, segundo os diferentes contextos históricos, sociais e culturais. Pertence ao Magistério discernir a sua fidelidade à tradição da fé apostólica e aos pastores e catequistas o explicar-lhe o sentido, que é sempre referido a Jesus Cristo." },
                new() { Titulo = "560. Qual é o caminho da nossa oração?", Texto = "O caminho da nossa oração é Cristo, porque ela se dirige a Deus nosso Pai, mas aquela só chega até Ele, se, ao menos implicitamente, rezamos no Nome de Jesus. A sua humanidade é, pois, o único caminho pelo qual o Espírito Santo nos ensina a rezar a Deus nosso Pai. Por isso as orações litúrgicas concluem-se com a fórmula: «Por nosso Senhor Jesus Cristo»." },
                new() { Titulo = "561. Qual o papel do Espírito Santo na oração?", Texto = "Uma vez que o Espírito Santo é o Mestre interior da oração cristã e «nós não sabemos o que devemos pedir» (Rm 8,26), a Igreja exorta-nos a invocá-lo e a implorá-lo em todas as ocasiões: «Vinde, Espírito Santo!»." },
                new() { Titulo = "562. Em que é que a oração cristã é mariana?", Texto = "Em virtude da sua singular cooperação com a acção do Espírito Santo, a Igreja gosta de orar a Maria e de orar com Maria, a Orante perfeita, para com Ela engrandecer e invocar o Senhor. De facto, Maria, «mostra-nos o caminho» que é o Seu Filho, o único Mediador." },
                new() { Titulo = "563. Como é que a Igreja reza a Maria?", Texto = "Antes de mais com a Ave Maria, oração mediante a qual a Igreja pede a intercessão da Virgem. Outras orações marianas são o Rosário o hino Acatistos, a Paraclisis, os hinos e os cânticos das diversas tradições cristãs." },
                new() { Titulo = "564. Como é que os Santos são guias de oração?", Texto = "Os santos são modelos de oração e a eles pedimos para, junto da Santíssima Trindade, intercederem por nós e pelo mundo inteiro. A sua intercessão é o mais alto serviço que prestam ao desígnio de Deus. Na comunhão dos santos, desenvolveram-se, ao longo da história da Igreja, diversos tipos de espiritualidade, que ensinam a viver e a pôr em prática a oração." },
                new() { Titulo = "565. Quem pode educar na oração?", Texto = "A família cristã é o primeiro lugar da educação na oração. A oração familiar quotidiana é especialmente recomendada porque é o primeiro testemunho da vida de oração da Igreja. A catequese, os grupos de oração, a «direcção espiritual» constituem uma ajuda e uma escola de oração." },
                new() { Titulo = "566. Quais os lugares favoráveis à oração?", Texto = "Em toda a parte se pode rezar, mas a escolha de um lugar apropriado não é indiferente para a oração. A igreja é o lugar próprio da oração litúrgica e da adoração eucarística. Também outros lugares ajudam a rezar, como um «recanto de oração» em casa; um mosteiro; um santuário." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "A Vida de Oração",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "567. Quais os momentos mais indicados para a oração?", Texto = "Todos os momentos são indicados para a oração, mas a Igreja propõe aos fiéis ritmos destinados a alimentar a oração contínua: orações da manhã e da noite, antes e depois das refeições, liturgia das Horas; Eucaristia dominical; Santo Rosário; festas do ano litúrgico." },
                new() { Titulo = "568. Quais as expressões da vida de oração?", Texto = "A tradição cristã conservou três modos para expressar e viver a oração: a oração vocal, a meditação e a oração contemplativa. Têm em comum o recolhimento do coração." },
                new() { Titulo = "569. Como se caracteriza a oração vocal?", Texto = "A oração vocal associa o corpo à oração interior do coração. Mesmo a mais interior das orações não poderia prescindir da oração vocal. Em todo o caso, ela deve brotar duma fé pessoal. Com o Pai Nosso, Jesus ensinou-nos uma fórmula perfeita de oração vocal." },
                new() { Titulo = "570. O que é a meditação?", Texto = "A meditação é uma reflexão orante, que parte sobretudo da Palavra de Deus na Bíblia. Mobiliza a inteligência, a imaginação, a emoção, o desejo, para aprofundar a nossa fé, suscitar a conversão do nosso coração e fortalecer a nossa vontade de seguir a Cristo. É uma etapa preliminar em direcção à união de amor com o Senhor." },
                new() { Titulo = "571. O que é a oração contemplativa?", Texto = "A oração contemplativa é um simples olhar sobre Deus no silêncio e no amor. É um dom de Deus, um momento de fé pura durante o qual o orante procura Cristo, se entrega à vontade amorosa do Pai e concentra o seu ser sob a acção do Espírito. Santa Teresa de Ávila define-a como uma íntima relação de amizade, «em que muitas vezes dialogamos a sós com Deus, por Quem sabemos ser amados»." },
                new() { Titulo = "572. Porque é que a oração é um combate?", Texto = "A oração é um dom da graça, mas pressupõe sempre uma resposta decidida da nossa parte, porque o que reza combate contra si mesmo, contra o ambiente e sobretudo contra o Tentador, que faz tudo para retirá-lo da oração. O combate da oração é inseparável do progresso da vida espiritual. Reza-se como se vive, porque se vive como se reza." },
                new() { Titulo = "573. Quais as objecções à oração?", Texto = "Para lá das formas erróneas de conceber a oração, muitos pensam que não têm tempo para rezar ou então que seja inútil. Os que rezam podem desanimar perante as dificuldades e os insucessos aparentes. Para vencer estes obstáculos são necessárias a humildade, a confiança e a perseverança." },
                new() { Titulo = "574. Quais as dificuldades da oração?", Texto = "A distracção é a dificuldade habitual da nossa oração. Ela afasta da atenção a Deus e pode também revelar aquilo a que estamos apegados. O nosso coração deve então regressar humildemente ao Senhor. A oração é muitas vezes insidiada pela aridez, cuja superação, na fé, permite aderir ao Senhor, mesmo sem uma consolação sensível. A acédia é uma forma de preguiça espiritual devida ao relaxamento da vigilância e à negligência na guarda do coração." },
                new() { Titulo = "575. Como fortalecer a nossa confiança filial?", Texto = "A confiança filial é posta à prova quando pensamos que não somos atendidos. Devemos interrogar-nos, então, se Deus é para nós um Pai do qual procuramos cumprir a vontade, ou não será antes um simples meio para obter o que queremos. Se a nossa oração se une à de Jesus, sabemos que Ele nos concede muito mais do que este ou aquele dom: recebemos o Espírito Santo que transforma o nosso coração." },
                new() { Titulo = "576. É possível rezar a todo o momento?", Texto = "Orar é sempre possível porque o tempo do cristão é o tempo de Cristo ressuscitado, o qual «permanece connosco todos os dias» (Mt 28,20). Oração e vida cristã são por isso inseparáveis." },
                new() { Titulo = "577. O que é a oração da Hora de Jesus?", Texto = "É a chamada oração sacerdotal de Jesus na Última Ceia. Jesus, o Sumo Sacerdote da Nova Aliança, dirige-a ao Pai quando chega a Hora da sua «passagem» para Ele, a Hora do seu sacrifício." },
            }
        },

        new CatecismoPtTopico
        {
            Titulo = "A Oração do Senhor: Pai Nosso",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "578. Qual é a origem da oração do Pai Nosso?", Texto = "Jesus ensinou-nos esta oração cristã insubstituível, o Pai Nosso, um dia quando um dos discípulos, vendo-O rezar, lhe pediu: «Ensina-nos a rezar» (Lc 11, 1). A tradição litúrgica da Igreja usou sempre o texto de S. Mateus (6, 9-13)." },
                new() { Titulo = "579. Qual é o lugar do Pai Nosso nas Escrituras?", Texto = "O Pai Nosso é a «síntese de todo o Evangelho» (Tertuliano), «a oração perfeitíssima» (S. Tomás de Aquino). Situado no centro do Discurso da Montanha (Mt 5-7), retoma, sob a forma de oração, o conteúdo essencial do Evangelho." },
                new() { Titulo = "580. Porque se chama «a oração do Senhor»?", Texto = "O Pai Nosso é a «Oração dominical», ou seja «a oração do Senhor», porque nos foi ensinado pelo próprio Senhor Jesus." },
                new() { Titulo = "581. Que lugar ocupa o Pai Nosso na oração da Igreja?", Texto = "O Pai Nosso é a oração da Igreja por excelência e é «entregue» no Baptismo para manifestar o novo nascimento para a vida divina dos filhos de Deus. A Eucaristia mostra-lhe o sentido pleno, visto que as suas petições, fundadas no mistério da salvação já realizada, e que serão plenamente atendidas na vinda do Senhor. O Pai Nosso é também parte integrante da liturgia das Horas." },
                new() { Titulo = "582. Porque podemos «ousar aproximar-nos com toda a confiança» do Pai?", Texto = "Porque Jesus, nosso Redentor, nos apresenta diante do Rosto do Pai, e o seu Espírito faz de nós filhos. Podemos assim rezar o Pai Nosso com uma confiança simples e filial, com uma alegre segurança e uma audácia humilde, com a certeza de ser amados e atendidos." },
                new() { Titulo = "583. Como é possível invocar a Deus como «Pai»?", Texto = "Podemos invocar o «Pai», porque Ele nos foi revelado por seu Filho feito homem e porque o seu Espírito no-Lo faz conhecer. A invocação do Pai introduz-nos no seu mistério com uma admiração sempre nova e suscita em nós o desejo dum comportamento filial. Ao rezar a oração do Senhor estamos conscientes de sermos filhos no Filho do eterno Pai." },
                new() { Titulo = "584. Porque dizemos «Pai Nosso»?", Texto = "«Nosso» exprime uma relação totalmente nova com Deus. Sempre que rezamos ao Pai, adoramo-Lo e glorificamo-Lo com o Filho e o Espírito. Em Cristo, somos o «seu» Povo e Ele é o «nosso» Deus, desde agora e para a eternidade. Dizemos, com efeito, Pai «nosso», porque a Igreja de Cristo é a comunhão duma multidão de irmãos que têm «um só coração e uma só alma» (Act 4,32)." },
                new() { Titulo = "585. Com que espírito de comunhão e missão dizemos ao rezar a Deus Pai «nosso»?", Texto = "Dado que rezar o Pai «nosso» é um bem comum de todos os baptizados, estes sentem o apelo urgente a participar na oração de Jesus pela unidade dos seus discípulos. Rezar o «Pai Nosso» é rezar com e por todos os homens, para que conheçam o único e verdadeiro Deus e sejam reunidos na unidade." },
                new() { Titulo = "586. Que significa a expressão «que estais nos céus»?", Texto = "Esta expressão bíblica não indica um lugar mas uma maneira de ser: Deus está para lá e acima de tudo. Designa a majestade, a santidade de Deus, e também a sua presença no coração dos justos. O céu, ou a Casa do Pai, constitui a verdadeira pátria para a qual tendemos na esperança, enquanto estamos ainda na terra. Nós vivemos já nela «escondidos com Cristo em Deus» (Col 3, 3)." },
                new() { Titulo = "587. Como é composta a oração do Senhor?", Texto = "A oração do Senhor contém sete petições a Deus Pai. As primeiras três, mais teologais, aproximam-nos d'Ele, para a sua glória: pois é próprio do amor pensar antes de mais n'Aquele que amamos. Elas sugerem o que em especial devemos pedir-Lhe: a santificação do seu Nome, a vinda do seu Reino, a realização da sua Vontade. As últimas quatro apresentam ao Pai de misericórdia as nossas misérias e as nossas expectativas. Pedimos que nos alimente, nos perdoe, nos defenda nas tentações e nos livre do Maligno." },
                new() { Titulo = "588. O que quer dizer «santificado seja o Vosso nome»?", Texto = "Santificar o Nome de Deus é, antes de mais, um louvor que reconhece Deus como Santo. De facto, Deus revelou o seu santo Nome a Moisés e quis que o seu povo lhe fosse consagrado como uma nação santa na qual Ele habita." },
                new() { Titulo = "589. Como é santificado o Nome de Deus em nós e no mundo?", Texto = "Santificar o Nome de Deus que nos chama «à santificação» (1 Tes 4,7) é desejar que a consagração baptismal vivifique toda a nossa vida. É pedir, além disso, com a nossa vida e a nossa oração, que o Nome de Deus seja conhecido e bendito por todos os homens." },
                new() { Titulo = "590. Que pede a Igreja rezando: «Venha a nós o vosso Reino»?", Texto = "A Igreja pede a vinda final do Reino de Deus mediante o regresso de Cristo na glória. Mas a Igreja reza, também, para que o Reino de Deus cresça, já hoje, graças à santificação dos homens no Espírito e graças ao seu empenho ao serviço da justiça e da paz, segundo as Bem-aventuranças. Este pedido é o grito do Espírito e da Esposa: «Vem Senhor Jesus» (Ap 22,20)." },
                new() { Titulo = "591. Porque pedir: «Seja feita a Vossa vontade assim na terra como no céu»?", Texto = "A vontade do Pai é que «todos os homens sejam salvos» (1 Tim 2,3). Para isso é que Jesus veio: para realizar perfeitamente a Vontade salvífica do Pai. Nós pedimos a Deus Pai que una a nossa vontade à do seu Filho, a exemplo de Maria Santíssima e dos Santos. Pedimos que o seu desígnio de benevolência se realize plenamente na terra como no céu. É mediante a oração que podemos «discernir a vontade de Deus» (Rm 12,2) e obter a «perseverança para a cumprir» (Heb 10, 36)." },
                new() { Titulo = "592. Que significa o pedido: «O pão nosso de cada dia nos dai hoje»?", Texto = "Ao pedir a Deus, com o confiante abandono dos filhos, o alimento quotidiano necessário a todos para a subsistência, reconhecemos o quanto Deus nosso Pai é bom e está acima de toda a bondade. Pedimos também a graça de saber agir de modo que a justiça e a partilha façam com que a abundância de uns possa prover às necessidades dos outros." },
                new() { Titulo = "593. Qual é o específico sentido cristão deste pedido?", Texto = "Porque «o homem não vive só de pão, mas de toda a palavra que sai da boca de Deus» (Mt 4,4), este pedido refere-se igualmente à fome da Palavra de Deus e à do Corpo de Cristo recebido na Eucaristia, bem como à fome do Espírito Santo. Pedimo-Lo, com uma confiança absoluta, para hoje, o hoje de Deus, o qual nos é dado sobretudo na Eucaristia que antecipa o banquete do reino que há-de vir." },
                new() { Titulo = "594. Porque dizer: «Perdoai-nos as nossas ofensas assim como nós perdoamos a quem nos tem ofendido»?", Texto = "Ao pedir a Deus Pai para nos perdoar, reconhecemo-nos pecadores diante d'Ele. E, ao mesmo tempo, confessamos a sua misericórdia, porque, no seu Filho e através dos sacramentos, «recebemos a redenção, o perdão dos pecados» (Col 1,14). Porém, o nosso pedido só será atendido se tivermos perdoado aos que nos ofenderam." },
                new() { Titulo = "595. Como é que é possível o perdão?", Texto = "A misericórdia penetra no nosso coração só se também nós soubermos perdoar, até aos nossos inimigos. Ora, mesmo que ao homem pareça impossível satisfazer esta exigência, o coração que se oferece ao Espírito Santo pode, como Cristo, amar até ao extremo do amor, mudar a ferida em compaixão, transformar a ofensa em intercessão. O perdão participa da misericórdia divina e é um vértice da oração cristã." },
                new() { Titulo = "596. O que significa: «Não nos deixeis cair em tentação»?", Texto = "Pedimos a Deus Pai que não nos deixe sozinhos e à mercê da tentação. Pedimos ao Espírito para sabermos discernir entre a provação que ajuda a crescer no bem e a tentação que conduz ao pecado e à morte, e, ainda, entre ser tentados e consentir na tentação. Esta petição coloca-nos em união com Jesus, que, com a sua oração, venceu a tentação e solicita a graça da vigilância e da perseverança final." },
                new() { Titulo = "597. Porque concluímos pedindo: «Mas livra-nos do Mal»?", Texto = "O Mal indica a pessoa de Satanás que se opõe a Deus e que é «o sedutor de toda a terra» (Ap 12, 9). A vitória sobre o diabo já foi alcançada por Cristo. Mas nós pedimos para que a família humana seja libertada de Satanás e das suas obras. Pedimos também o dom precioso da paz e a graça da esperança perseverante da vinda de Cristo, que nos libertará definitivamente do Maligno." },
                new() { Titulo = "598. O que significa o Ámen final?", Texto = "«Depois, acabada a oração, tu dizes: Ámen, corroborando com o Ámen, que significa \"Assim seja, que isso se faça\", tudo o que está contido na oração que Deus nos ensinou» (S. Cirilo de Jerusalém)." },
            }
        },

        // ─────────────────────────────────────────────────────────────────────
        // ORAÇÕES TRADICIONAIS CATÓLICAS
        // ─────────────────────────────────────────────────────────────────────

        new CatecismoPtTopico
        {
            Titulo = "Orações",
            CatecismosPt = new List<CatecismoPt>
            {
                new() { Titulo = "Pai Nosso", Texto = "Pai Nosso que estais nos céus,\nsantificado seja o Vosso nome,\nvenha a nós o Vosso reino,\nseja feita a Vossa vontade\nassim na terra como no céu.\nO pão nosso de cada dia nos dai hoje,\nperdoai-nos as nossas ofensas\nassim como nós perdoamos\na quem nos tem ofendido,\ne não nos deixeis cair em tentação,\nmas livrai-nos do Mal.\nÁmen." },
                new() { Titulo = "Ave Maria", Texto = "Ave Maria, cheia de graça,\no Senhor é convosco;\nbendita sois vós entre as mulheres,\ne bendito é o fruto do vosso ventre, Jesus.\nSanta Maria, Mãe de Deus,\nrogai por nós pecadores,\nagora e na hora da nossa morte.\nÁmen." },
                new() { Titulo = "Glória ao Pai", Texto = "Glória ao Pai, e ao Filho, e ao Espírito Santo.\nAssim como era no princípio,\nagora e sempre,\npor todos os séculos dos séculos.\nÁmen." },
                new() { Titulo = "Credo dos Apóstolos", Texto = "Creio em Deus Pai todo-poderoso,\nCriador do céu e da terra.\nE em Jesus Cristo, seu único Filho, Nosso Senhor,\nque foi concebido pelo poder do Espírito Santo,\nnasceu da Virgem Maria,\npadeceu sob Pôncio Pilatos,\nfoi crucificado, morto e sepultado,\ndesceu à mansão dos mortos,\nressuscitou ao terceiro dia,\nsubiu aos céus,\nestá sentado à direita de Deus Pai todo-poderoso,\ndonde há-de vir julgar os vivos e os mortos.\nCreio no Espírito Santo,\nna Santa Igreja Católica,\nna comunhão dos Santos,\nna remissão dos pecados,\nna ressurreição da carne,\nna vida eterna.\nÁmen." },
                new() { Titulo = "Credo Niceno-Constantinopolitano", Texto = "Creio em um só Deus,\nPai todo-poderoso,\nCriador do céu e da terra,\nde todas as coisas visíveis e invisíveis.\nCreio em um só Senhor, Jesus Cristo,\nFilho Unigênito de Deus,\nnascido do Pai antes de todos os séculos:\nDeus de Deus, luz da luz,\nDeus verdadeiro de Deus verdadeiro;\ngerado, não criado, consubstancial ao Pai.\nPor Ele todas as coisas foram feitas.\nE por nós, homens, e para nossa salvação,\ndesceu dos céus:\npelo poder do Espírito Santo,\nencarnOU na Virgem Maria\ne se fez homem.\nTambém por nós foi crucificado sob Pôncio Pilatos;\npadeceu e foi sepultado.\nRessuscitou ao terceiro dia,\ncomo está escrito nas Escrituras.\nSubiu aos céus\ne está sentado à direita do Pai.\nE de novo há-de vir, em glória,\npara julgar os vivos e os mortos;\ne o seu Reino não terá fim.\nCreio no Espírito Santo,\nSenhor que dá a vida,\nque procede do Pai e do Filho;\ncom o Pai e o Filho é adorado e glorificado;\nfalou pelos profetas.\nCreio na Igreja una, santa, católica e apostólica.\nProfesso um único batismo\npara remissão dos pecados.\nAguardo a ressurreição dos mortos\ne a vida do mundo que há-de vir.\nÁmen." },
                new() { Titulo = "Ato de Contrição", Texto = "Meu Deus, porque sois infinitamente bom\ne porque o pecado vos desgrada,\narrependo-me de todo o coração de Vos ter ofendido,\ne proponho firmemente,\ncom o auxílio da vossa graça,\nnão mais pecar\ne afastar tudo o que me leve ao pecado.\nÁmen." },
                new() { Titulo = "Ato de Fé", Texto = "Meu Deus, creio em Vós\nporque sois a Verdade eterna,\nque nos revelastes o que cremos.\nCreio em tudo o que a Santa Igreja Católica\nnos propõe para crer,\nporque Vós o revelastes.\nÁmen." },
                new() { Titulo = "Ato de Esperança", Texto = "Meu Deus, espero em Vós,\npelo mérito de Jesus Cristo,\na remissão dos meus pecados,\na graça de perseverar no bem\ne a vida eterna,\nporque Vós o prometestes\ne sois fiel nas vossas promessas.\nÁmen." },
                new() { Titulo = "Ato de Caridade", Texto = "Meu Deus, amo-vos sobre todas as coisas,\ncom todo o meu coração,\nporque sois infinitamente bom\ne digno de todo o amor.\nAmo também o meu próximo como a mim mesmo\npor amor de Vós.\nÁmen." },
                new() { Titulo = "Oração antes das Refeições", Texto = "Bendize, Senhor,\nestes alimentos que vamos tomar\ne a todos os que os prepararam.\nLembra-Te dos que passam necessidade.\nÁmen." },
                new() { Titulo = "Oração depois das Refeições", Texto = "Graças Te damos, Senhor,\npor todos os benefícios recebidos,\nque vives e reinas por todos os séculos dos séculos.\nÁmen." },
                new() { Titulo = "Oração da Manhã", Texto = "Senhor meu Deus,\nofereço-Vos este dia:\nminhas orações, obras, alegrias e sofrimentos,\nem união com Jesus Cristo vosso Filho,\nem reparação pelos pecados,\npela conversão dos pecadores,\npelas intenções do Santo Padre\ne pelas necessidades da Santa Igreja.\nÁmen." },
                new() { Titulo = "Oração da Noite", Texto = "Senhor, obrigado por este dia.\nPerdoa-me os erros que cometi,\nguarda-me durante esta noite\ne protege todos os que amo.\nFaz que amanhã possa servir-Te melhor\ne ser instrumento da Tua paz.\nÁmen." },
                new() { Titulo = "Memorare", Texto = "Lembrai-Vos, ó piíssima Virgem Maria,\nque jamais se ouviu dizer\nque alguém que tivesse recorrido\nà Vossa proteção,\nimplorado Vosso auxílio\ne invocado o Vosso socorro,\ntivesse sido abandonado.\nAnimado por essa confiança,\na Vós me refugio, ó Mãe das virgens;\na Vós venho, diante de Vós me prostro,\npecador arrependido.\nNão desprezeis as minhas palavras,\nó Mãe do Verbo encarnado,\nmas ouvi-me e atendei-me\nna Vossa misericórdia.\nÁmen." },
                new() { Titulo = "Salve Rainha", Texto = "Salve, Rainha, Mãe de misericórdia,\nvida, doçura e esperança nossa, salve!\nA Vós bradamos, os degredados filhos de Eva;\na Vós suspiramos, gemendo e chorando\nneste vale de lágrimas.\nÓ pois, advogada nossa,\nesses Vossos olhos misericordiosos a nós volvei;\ne depois deste desterro nos mostrai\nJesus, o bendito fruto do Vosso ventre.\nÓ clemente, ó piedosa, ó doce Virgem Maria.\nRogai por nós, Santa Mãe de Deus,\npara que sejamos dignos das promessas de Cristo.\nÁmen." },
                new() { Titulo = "Angelus", Texto = "O Anjo do Senhor anunciou a Maria.\nE ela concebeu pelo Espírito Santo.\nAve Maria...\nEis aqui a Escrava do Senhor.\nFaça-se em mim segundo a Vossa palavra.\nAve Maria...\nE o Verbo se fez carne.\nE habitou entre nós.\nAve Maria...\nRogai por nós, Santa Mãe de Deus.\nPara que sejamos dignos das promessas de Cristo.\nOremos:\nInfundi, Senhor, no nosso espírito a Vossa graça,\npara que os que pela anunciação do anjo\nconhecemos a encarnação de Cristo Vosso Filho,\npela Sua paixão e cruz sejamos levados\nà glória da ressurreição.\nPor Cristo Nosso Senhor. Ámen." },
                new() { Titulo = "Regina Coeli", Texto = "Alegra-te, Rainha do Céu, aleluia!\nO Filho que mereces ter, aleluia,\nressuscitou como disse, aleluia!\nRoga ao Senhor por nós, aleluia!\nGozai e alegrai-Vos, ó Virgem Maria, aleluia!\nPorque o Senhor ressuscitou verdadeiramente, aleluia!\nOremos:\nÓ Deus, que pelo Vosso Filho Unigénito nos destes a alegria da ressurreição;\nconcedei que nós, com a intercessão da Virgem Maria, Sua Mãe,\nalcancemos a alegria da vida eterna.\nPor Cristo, Nosso Senhor. Ámen." },
                new() { Titulo = "Oração de São Francisco de Assis", Texto = "Senhor, fazei de mim um instrumento da Vossa paz.\nOnde houver ódio, que eu leve o amor;\nonde houver ofensa, que eu leve o perdão;\nonde houver discórdia, que eu leve a união;\nonde houver dúvida, que eu leve a fé;\nonde houver erro, que eu leve a verdade;\nonde houver desespero, que eu leve a esperança;\nonde houver tristeza, que eu leve a alegria;\nonde houver trevas, que eu leve a luz.\nÓ Mestre, fazei que eu procure\nmais consolar do que ser consolado;\nmais compreender do que ser compreendido;\nmais amar do que ser amado.\nPorque é dando que se recebe;\nperdonado que se é perdoado;\nee é morrendo que se vive para a vida eterna.\nÁmen." },
                new() { Titulo = "Oração ao Espírito Santo", Texto = "Vem, Espírito Santo,\nenche os corações dos Teus fiéis\ne acende neles o fogo do Teu amor.\nEnviai, ó Senhor, o Vosso Espírito,\ne tudo será criado;\ne renovareis a face da terra.\nOremos:\nÓ Deus, que instruístes os corações dos Vossos fiéis\ncom a luz do Espírito Santo;\nconcedei-nos que, pelo mesmo Espírito,\npossamos conhecer o bem que é reto,\ne gozar sempre do Seu consolo.\nPor Jesus Cristo Nosso Senhor.\nÁmen." },
                new() { Titulo = "Sub Tuum Praesidium", Texto = "Sob a Vossa proteção nos acolhemos,\nSanta Mãe de Deus;\nnão desprezeis as nossas súplicas em nossas necessidades;\nmas livrai-nos sempre de todos os perigos,\nó Virgem gloriosa e bendita.\nÁmen." },
                new() { Titulo = "Magnificat", Texto = "Proclama a minha alma a grandeza do Senhor,\nexulta o meu espírito em Deus, meu Salvador,\nporque olhou para a humildade da Sua serva.\nDesde agora me chamarão bem-aventurada todas as gerações,\nporque o Todo-Poderoso fez grandes coisas em mim.\nSanto é o Seu nome!\nA Sua misericórdia vai de geração em geração,\npara aqueles que O respeitam.\nMostrou o poder do Seu braço,\ndispersou os que têm pensamentos soberbos.\nDerrubou os poderosos do seu trono,\nexaltou os humildes.\nCumulou de bens os famintos,\nenviou os ricos de mãos vazias.\nSocorreu Israel, Seu servo,\nlembrado da Sua misericórdia,\ncomo prometera aos nossos pais,\nem favor de Abraão e da sua descendência para sempre.\nGlória ao Pai, e ao Filho e ao Espírito Santo.\nAssim como era no princípio, agora e sempre,\npor todos os séculos dos séculos. Ámen." },
                new() { Titulo = "Benedictus", Texto = "Bendito seja o Senhor, Deus de Israel,\nporque visitou e remiu o Seu povo,\ne suscitou para nós o poder da salvação\nna casa de David, Seu servo,\ncomo havia prometido pela boca dos Seus santos profetas:\nque nos salvaria dos nossos inimigos\ne da mão de todos os que nos odeiam.\nAssim Se compadeceu dos nossos pais\ne Se lembrou da Sua santa aliança,\ndo juramento que jurou a Abraão, nosso pai,\nde nos conceder, livres das mãos dos nossos inimigos,\nque O servíssemos sem temor,\nem santidade e justiça diante d'Ele, todos os nossos dias.\nE tu, criança, serás chamado profeta do Altíssimo,\npois irás diante do Senhor para preparar os Seus caminhos,\npara dar ao Seu povo o conhecimento da salvação,\nna remissão dos seus pecados.\nPela ternura da misericórdia do nosso Deus,\ncom que nos visitará do alto o Sol que nasce,\npara iluminar os que jazem nas trevas e na sombra da morte,\npara guiar os nossos passos no caminho da paz.\nGlória ao Pai, e ao Filho e ao Espírito Santo.\nAssim como era no princípio, agora e sempre,\npor todos os séculos dos séculos. Ámen." },
                new() { Titulo = "Nunc Dimittis", Texto = "Agora, Senhor, podeis deixar o Vosso servo partir em paz,\nconforme a Vossa palavra;\nporque os meus olhos viram a Vossa salvação,\nque haveis preparado diante de todos os povos:\nluz para iluminar as nações,\ne glória do Vosso povo Israel.\nGlória ao Pai, e ao Filho e ao Espírito Santo.\nAssim como era no princípio, agora e sempre,\npor todos os séculos dos séculos. Ámen." },
                new() { Titulo = "Oração para Comunhão Espiritual", Texto = "Meu Jesus, creio que estais no Santíssimo Sacramento.\nAmo-Vos acima de todas as coisas\ne desejo-Vos na minha alma.\nDado que agora não posso receber-Vos sacramentalmente,\nvinde ao menos espiritualmente ao meu coração.\nComo se já tivésseis vindo,\nabraço-Vos e uno-me todo a Vós;\nnão permitais que me separe de Vós.\nÁmen." },
                new() { Titulo = "Oração pelos Fiéis Defuntos", Texto = "Senhor, dai o descanso eterno a todas as almas dos fiéis defuntos\ne que a luz perpétua os ilumine.\nDescansem em paz.\nÁmen.\nDa porta do inferno,\nlivrai as suas almas, ó Senhor.\nQue repousem em paz. Ámen.\nÓ Senhor, ouvi a minha oração,\ne que o meu clamor chegue até Vós.\nOremos:\nDeus, Criador e Redentor de todos os fiéis,\ndai às almas dos Vossos servos e servas a remissão de todos os pecados,\npara que, pelo auxílio das nossas súplicas piedosas,\nobtenham o perdão que sempre desejaram.\nVós que viveis e reinais pelos séculos dos séculos.\nÁmen." },
                new() { Titulo = "De Profundis (Salmo 129)", Texto = "Das profundezas clamo a Vós, Senhor;\nSenhor, ouvi a minha voz!\nEstejam atentos os Vossos ouvidos\nàs vozes da minha súplica.\nSe guardardes, Senhor, as iniquidades,\nSenhor, quem subsistirá?\nMas em Vós está a misericórdia,\ne por causa da Vossa lei esperei em Vós, Senhor.\nA minha alma esperou no Senhor.\nDa manhã até à noite,\nespere Israel no Senhor!\nPorque no Senhor está a misericórdia,\ne nele está a redenção abundante.\nE Ele remirá Israel de todas as suas iniquidades.\nDescansem em paz. Ámen." },
                new() { Titulo = "Oração de Santo Anselmo", Texto = "Senhor meu Deus,\nensinai ao meu coração onde e como Vos procurar,\nonde e como Vos encontrar.\nSenhor, se não estais aqui, onde vos hei de procurar,\nestando ausente?\nSe estais em todo o lado, por que não Vos vejo?\nTendes criado tudo e eu sou uma das Vossas criaturas.\nAlcançai a minha alma para que ela se lembre de Vós,\npara que Vos conheça e Vos ame.\nÁmen." },
                new() { Titulo = "Oração de Santa Teresa de Ávila", Texto = "Que nada te perturbe,\nque nada te asuste;\ntudo passa,\nDeus não muda.\nA paciência tudo alcança.\nQuem a Deus tem,\nnada lhe falta.\nSó Deus basta." },
            }
        },
    };
}
